// ─── Quiz (120+ questions) ───
const QUIZ = [
  // Ch.1 — Prise en main (15 questions)
  { q: "Un Data Analyst veut afficher un CA dynamique filtrable. Quelle approche ?", o: ["Colonne calculée", "Mesure = SUM(Sales[SalesAmount])", "CALCULATE sans filtre", "Glisser SalesAmount directement"], a: 1, d: "MO", ch: 1, w: "Une mesure est recalculée dynamiquement selon les filtres. Une colonne calculée est statique." },
  { q: "DIVIDE(A, B, 0) — le 0 ?", o: ["Multiplie par 0", "Retourne 0 si B=0", "Arrondit à 0", "Ignore NULL"], a: 1, d: "MO", ch: 1, w: "Valeur de remplacement si dénominateur = 0." },
  { q: "Différence entre COUNT et DISTINCTCOUNT ?", o: ["Identiques", "DISTINCTCOUNT est plus lent", "COUNT = avec doublons, DISTINCTCOUNT = uniques", "COUNT ne marche pas sur du texte"], a: 2, d: "MO", ch: 1, w: "COUNT compte toutes les lignes (avec doublons). DISTINCTCOUNT = valeurs uniques." },
  { q: "Tu veux afficher le CA Total comme un grand chiffre unique, sans tableau ni graphe. Quel visuel ?", o: ["Table avec une seule ligne", "KPI (avec indicateur de tendance)", "Jauge", "Carte"], a: 3, d: "VA", ch: 1, w: "Carte = un seul chiffre. KPI = chiffre + tendance (nécessite un objectif). Jauge = jauge (nécessite min/max). Table = trop détaillé pour un seul chiffre." },
  { q: "Les 3 composants de l'écosystème Power BI ?", o: ["Desktop, Service, Mobile", "Desktop, Cloud, API", "Desktop, Server, Gateway", "Report, Dataset, Dashboard"], a: 0, d: "DE", ch: 1, w: "Desktop (création) + Service (cloud/partage) + Mobile (consultation)." },
  { q: "Pour partager un rapport via un workspace, quelle licence minimum ?", o: ["Free", "Pro", "Premium", "Enterprise"], a: 1, d: "DE", ch: 1, w: "Free = mon espace seulement. Pro = workspace partagé." },
  { q: "Mesure vs colonne calculée — laquelle utiliser pour un KPI ?", o: ["Colonne calculée (plus rapide)", "Les deux sont identiques", "Mesure (dynamique selon filtres)", "Aucune, utiliser le champ directement"], a: 2, d: "MO", ch: 1, w: "Mesure = dynamique (95% des cas). Colonne = statique (5%)." },
  { q: "Tu cliques sur la barre 'France' d'un bar chart. Tous les autres visuels de la page se mettent à jour. C'est :", o: ["Le filtrage par CALCULATE", "Le RLS (Row-Level Security)", "Le extraction vers une autre page", "Le filtrage croisé (interaction entre visuels)"], a: 3, d: "VA", ch: 1, w: "Filtrage croisé = interaction entre visuels de la même page. CALCULATE modifie le contexte dans une formule DAX. RLS filtre par utilisateur. Extraction navigue entre pages." },

  // Ch.2 — Power Query (15 questions)
  { q: "Une colonne contient des NULL et des types incorrects. Où corriger ?", o: ["Power Query (avant le chargement)", "DAX (mesure de nettoyage)", "Vue Données (modification manuelle)", "Fichier source directement"], a: 0, d: "PQ", ch: 2, w: "Power Query = nettoyage (ETL). DAX = calculs analytiques. La vue Données est en lecture seule. Modifier la source ne garantit pas la reproductibilité." },
  { q: "SUM(Sales[Montant]) retourne une erreur car la colonne Montant est en type Texte. Quelle est la MEILLEURE correction ?", o: ["Créer une mesure avec VALUE(Sales[Montant])", "Changer le type en Nombre décimal dans Power Query", "Utiliser SUMX avec CONVERT", "Modifier le fichier source et recharger"], a: 1, d: "PQ", ch: 2, w: "PQ convertit une seule fois au chargement (performant). VALUE() en DAX reconvertit à chaque calcul (lent). Modifier la source n'est pas reproductible." },
  { q: "Merge Queries = équivalent SQL de :", o: ["UNION", "GROUP BY", "JOIN", "PIVOT"], a: 2, d: "PQ", ch: 2, w: "Merge = jointure (JOIN). Append = empilement (UNION)." },
  { q: "Append Queries = équivalent SQL de :", o: ["JOIN", "SUBQUERY", "GROUP BY", "UNION"], a: 3, d: "PQ", ch: 2, w: "Append = empiler des lignes (UNION). Merge = ajouter des colonnes (JOIN)." },
  { q: "Après un Merge, la colonne affiche 'Table'. Pourquoi ?", o: ["Il faut Expand les colonnes", "Bug Power Query", "La jointure a échoué", "Types incompatibles"], a: 0, d: "PQ", ch: 2, w: "Après un Merge, cliquer sur Expand (↔) pour développer les colonnes." },
  { q: "Structure du langage M ?", o: ["BEGIN/END", "let/in", "SELECT/FROM", "function/return"], a: 1, d: "PQ", ch: 2, w: "let (étapes séquentielles) ... in (résultat final)." },
  { q: "Unpivot sert à :", o: ["Supprimer des colonnes", "Créer un pivot table", "Transformer des colonnes en lignes", "Trier les données"], a: 2, d: "PQ", ch: 2, w: "Quand Excel a les mois en colonnes, Unpivot les transforme en lignes." },
  { q: "Quel geste en premier dans Power Query ?", o: ["Supprimer colonnes", "Renommer", "Filtrer les lignes", "Vérifier les types"], a: 3, d: "PQ", ch: 2, w: "Types en premier. Un type incorrect cause des erreurs en cascade." },
  { q: "Colonne conditionnelle dans PQ : quel langage ?", o: ["M (Power Query)", "DAX", "SQL", "Python"], a: 0, d: "PQ", ch: 2, w: "PQ utilise M. DAX est pour les mesures/colonnes dans le modèle." },

  // Ch.3 — Modélisation (15 questions)
  { q: "Quelle est la différence principale entre un schéma en étoile et un schéma en flocon ?", o: ["Le flocon n'a pas de table de faits", "L'étoile a les dimensions directement reliées aux faits, le flocon normalise les dimensions entre elles", "L'étoile est pour les petits modèles, le flocon pour les grands", "Il n'y a pas de différence, ce sont des synonymes"], a: 1, d: "MO", ch: 3, w: "Étoile = dimensions directement reliées aux faits. Flocon = dimensions normalisées (Product → SubCategory → Category). Power BI recommande l'étoile." },
  { q: "Relation N:N entre Product et Sales. Solution ?", o: ["Filtrage Both", "CALCULATE sans relation", "Table pont", "Fusionner dans PQ"], a: 2, d: "MO", ch: 3, w: "Table pont = solution propre. Both = ambiguïtés." },
  { q: "Pourquoi une table de dates séparée ?", o: ["Esthétique", "Remplacer les segments", "Réduire la taille", "Time Intelligence + hiérarchie"], a: 3, d: "MO", ch: 3, w: "TOTALYTD, SAMEPERIODLASTYEAR nécessitent une table dates continue et marquée." },
  { q: "Direction de filtre recommandée ?", o: ["Single (dimension → faits)", "Both", "Aucune", "Cross-filter off"], a: 0, d: "MO", ch: 3, w: "Single = naturel. Both crée des ambiguïtés." },
  { q: "USERELATIONSHIP sert à :", o: ["Créer une relation", "Activer une inactive dans CALCULATE", "Supprimer une relation", "Changer cardinalité"], a: 1, d: "MO", ch: 3, w: "Active ponctuellement une relation inactive." },
  { q: "Table de dates — 3 prérequis ?", o: ["Licence Pro + marquage + hiérarchie", "2 ans de données + PQ + marquage", "Continue + marquée + relation active", "PQ configuré + type date + index"], a: 2, d: "MO", ch: 3, w: "Continue (chaque jour), marquée comme table de dates, relation active avec la table de faits." },
  { q: "RLS créé dans Desktop mais non appliqué. Pourquoi ?", o: ["Incompatible Service", "Modèle incorrect", "Licence Premium requise", "Rôles doivent être assignés dans Service"], a: 3, d: "DE", ch: 3, w: "Créer ≠ appliquer. Assigner dans Service → Dataset → Sécurité." },
  { q: "Carteinalité la plus fréquente ?", o: ["1:N", "1:1", "N:N", "N:1"], a: 0, d: "MO", ch: 3, w: "1:N dans 95% des cas. 1 produit → N ventes." },

  // Ch.4 — CALCULATE (20 questions — le plus testé)
  { q: "CALCULATE([CA], Country='France') dans un visuel filtré Germany ?", o: ["CA Germany", "CA France", "France + Germany", "Erreur"], a: 1, d: "MO", ch: 4, w: "CALCULATE REMPLACE le filtre sur la même colonne." },
  { q: "CALCULATE modifie :", o: ["Les données source", "Le modèle de données", "Le contexte de filtre", "Les types de colonnes"], a: 2, d: "MO", ch: 4, w: "CALCULATE modifie le contexte de filtre, puis évalue l'expression." },
  { q: "Mesure comme filtre direct dans CALCULATE ?", o: ["Oui, toujours", "Impossible en DAX", "Oui avec KEEPFILTERS", "Non → utiliser FILTER"], a: 3, d: "MO", ch: 4, w: "CALCULATE n'accepte que des filtres sur colonnes. Pour une mesure → FILTER." },
  { q: "FILTER dans CALCULATE est :", o: ["Un itérateur ligne par ligne", "Un WHERE SQL", "Un filtre de page", "Un segment dynamique"], a: 0, d: "MO", ch: 4, w: "FILTER parcourt chaque ligne et évalue la condition." },
  { q: "KEEPFILTERS sert à :", o: ["Supprimer les filtres", "AJOUTER au lieu de REMPLACER", "Accélérer les calculs", "Désactiver RLS"], a: 1, d: "MO", ch: 4, w: "Force l'intersection au lieu du remplacement sur la même colonne." },
  { q: "CALCULATE([CA], Country='France', Category='Bikes') dans visuel Germany. Résultat ?", o: ["CA Germany + Bikes", "CA France + Germany + Bikes", "CA France + Bikes", "Erreur"], a: 2, d: "MO", ch: 4, w: "Country='France' REMPLACE Germany (même colonne). Category='Bikes' S'AJOUTE (autre colonne). Résultat = France + Bikes." },
  { q: "Pourquoi CALCULATE([CA], FILTER(Product, Price>1000)) au lieu de CALCULATE([CA], Price>1000) ?", o: ["Plus rapide", "Prix est une mesure", "Obligatoire en DAX", "FILTER permet les expressions complexes"], a: 3, d: "MO", ch: 4, w: "Filtre direct = valeur unique sur une colonne. FILTER = expression (>, <, combinaisons)." },
  { q: "CALCULATE([CA], ALL(Territory)) retourne :", o: ["CA total global (tous pays)", "CA du pays filtré", "Erreur", "BLANK"], a: 0, d: "MO", ch: 4, w: "ALL supprime les filtres sur Territory → total global." },
  { q: "Le contexte de filtre d'une cellule dans un tableau croisé est déterminé par :", o: ["L'ordre des colonnes", "L'intersection des filtres ligne/colonne/segment/page", "Le type de visuel", "La première mesure"], a: 1, d: "MO", ch: 4, w: "Chaque cellule = intersection de tous les filtres actifs." },
  { q: "CALCULATE est nécessaire quand :", o: ["On veut calculer une somme", "On utilise des segments", "On veut modifier le contexte de filtre", "Toujours"], a: 2, d: "MO", ch: 4, w: "CALCULATE = modifier le contexte. SUM/COUNTROWS n'ont pas besoin de CALCULATE pour fonctionner." },

  // Ch.5 — DAX Avancé (20 questions)
  { q: "% du total par pays → quelle fonction au dénominateur ?", o: ["FILTER", "ALLEXCEPT", "VALUES", "ALL dans CALCULATE"], a: 3, d: "MO", ch: 5, w: "ALL supprime les filtres → dénominateur = total global." },
  { q: "ALL vs ALLSELECTED ?", o: ["ALL ignore tout / ALLSELECTED respecte segments+RLS", "Identiques", "ALLSELECTED plus rapide", "ALL est déprécié"], a: 0, d: "MO", ch: 5, w: "ALL supprime TOUT. ALLSELECTED garde les filtres externes." },
  { q: "RANKX(Product, [CA]) retourne toujours 1. Pourquoi ?", o: ["Bug DAX", "Manque ALL() au 1er argument", "RANKX incompatible", "Tri incorrect"], a: 1, d: "MO", ch: 5, w: "Sans ALL, un seul produit dans le contexte → rang 1 systématique." },
  { q: "SWITCH(TRUE(), >1000,'Std', >10000,'VIP', 'Petit'). CA=15000 →", o: ["VIP", "Petit", "Std", "Erreur"], a: 2, d: "MO", ch: 5, w: "Évalue dans l'ORDRE. >1000 matche en premier. Inverser les conditions." },
  { q: "SUM vs SUMX — quand SUMX ?", o: ["Toujours", "Jamais, SUM suffit", "Table petite uniquement", "Calcul multi-colonnes par ligne"], a: 3, d: "MO", ch: 5, w: "SUMX évalue une expression par ligne puis somme." },
  { q: "ALL() sans argument dans CALCULATE fait quoi ?", o: ["Supprime tous les filtres du modèle entier", "Rien", "Erreur de syntaxe", "Supprime le filtre de la table courante"], a: 0, d: "MO", ch: 5, w: "ALL() sans argument = supprime TOUS les filtres de TOUT le modèle. Dangereux." },
  { q: "ALLEXCEPT(Territory, Territory[countryregioncode]) fait quoi ?", o: ["Supprime Country", "Garde Country, supprime le reste", "Erreur", "Identique à ALL(Territory)"], a: 1, d: "MO", ch: 5, w: "ALLEXCEPT supprime tout SAUF les colonnes spécifiées." },
  { q: "VAR dans DAX est évalué :", o: ["À chaque référence", "Au chargement du modèle", "Une seule fois (puis réutilisé)", "Jamais si non utilisé"], a: 2, d: "MO", ch: 5, w: "VAR = évalué 1 fois. Performance + lisibilité." },
  { q: "TOPN(5, ALL(Product), [CA]) retourne :", o: ["5 produits aléatoires", "Erreur sans CALCULATE", "Les 5 premiers de la table", "Les 5 produits avec le plus gros CA"], a: 3, d: "MO", ch: 5, w: "TOPN trie par [CA] DESC et retourne les 5 premiers." },
  { q: "RANKX : le 5e argument 'Dense' vs 'Skip' ?", o: ["Dense = pas de trous (1,2,2,3). Skip = trous (1,2,2,4)", "Identiques", "Dense plus lent", "Skip est le défaut"], a: 0, d: "MO", ch: 5, w: "Dense = rangs consécutifs. Skip = saute les rangs en cas d'égalité." },
  { q: "ALL supprime aussi le filtre RLS ?", o: ["Non, RLS est protégé", "Oui — problème de sécurité potentiel", "Seulement en Desktop", "Dépend de la licence"], a: 1, d: "MO", ch: 5, w: "ALL supprime TOUT y compris RLS. Utiliser ALLSELECTED pour garder RLS." },

  // Ch.6 — Time Intelligence (15 questions)
  { q: "Cumul depuis le 1er janvier = ?", o: ["DATEADD(-1, YEAR)", "TOTALYTD([CA], DateTable[Date])", "SAMEPERIODLASTYEAR", "CALCULATE([CA], ALL(Date))"], a: 1, d: "VA", ch: 6, w: "TOTALYTD = Year-To-Date." },
  { q: "TOTALYTD même résultat chaque mois. Cause ?", o: ["Bug DAX", "Visuel mal configuré", "Données incorrectes", "Mauvaise colonne date (pas la table marquée)"], a: 3, d: "VA", ch: 6, w: "Utiliser DateTable[Date] (table marquée), pas Orders[orderdate]." },
  { q: "DATEADD(Date, -1, MONTH) fait :", o: ["Décale le contexte d'un mois", "Supprime un mois de données", "Filtre le mois actuel", "Crée une colonne"], a: 0, d: "VA", ch: 6, w: "Retourne une table de dates décalée pour comparaison." },
  { q: "Prérequis Time Intelligence ?", o: ["Licence Pro", "Table dates continue + marquée + relation", "2 ans de données minimum", "PQ configuré"], a: 1, d: "VA", ch: 6, w: "Continue (chaque jour), marquée, relation active." },
  { q: "MoM % BLANK pour janvier. C'est :", o: ["Un bug à corriger", "Erreur de type", "Normal — pas de mois précédent", "Problème de relation"], a: 2, d: "VA", ch: 6, w: "DATEADD(-1 MONTH) pour jan → déc N-1. Si pas de données → BLANK." },
  { q: "SAMEPERIODLASTYEAR vs DATEADD(-1, YEAR) ?", o: ["Identiques", "SAMEPERIODLASTYEAR ne marche qu'avec des années", "DATEADD est déprécié", "SAMEPERIODLASTYEAR = mois exact, DATEADD = plus flexible"], a: 3, d: "VA", ch: 6, w: "SAMEPERIODLASTYEAR = raccourci pour DATEADD(-1, YEAR). DATEADD est plus flexible (-1 MONTH, -1 QUARTER)." },
  { q: "TOTALQTD calcule le cumul depuis :", o: ["Le début du trimestre en cours", "Le 1er janvier", "Le mois précédent", "La date minimale"], a: 0, d: "VA", ch: 6, w: "QTD = Quarter-To-Date. Cumul depuis le début du trimestre." },
  { q: "PARALLELPERIOD(-1, YEAR) vs SAMEPERIODLASTYEAR ?", o: ["Identiques", "PARALLELPERIOD = période COMPLÈTE décalée, SAMEPERIOD = même période", "PARALLELPERIOD est plus rapide", "SAMEPERIOD couvre plus de cas"], a: 1, d: "VA", ch: 6, w: "PARALLELPERIOD retourne la période complète (ex: année entière 2021). SAMEPERIOD retourne la même période exacte." },

  // Ch.7 — Visu, Service, Déployer (15 questions)
  { q: "'Publier sur le web' = :", o: ["Partager en Pro uniquement", "SharePoint", "Accessible à TOUS sans sécurité", "App mobile"], a: 2, d: "DE", ch: 7, w: "Zéro sécurité. Jamais pour données d'entreprise." },
  { q: "Refresh max en Pro :", o: ["1/jour", "Illimité", "48/jour", "8/jour"], a: 3, d: "DE", ch: 7, w: "Pro = 8/jour. PPU = 48/jour." },
  { q: "RLS 'France', mesure % avec ALL(Territory). Correct ?", o: ["Non — ALL supprime RLS", "Oui", "CALCULATE incompatible", "Oui si direction Both"], a: 0, d: "DE", ch: 7, w: "ALL supprime RLS → dénominateur global. Solution : ALLSELECTED." },
  { q: "Workspace role pour publier ?", o: ["Lecteur", "Contributeur", "Admin uniquement", "Tout le monde"], a: 1, d: "DE", ch: 7, w: "Contributeur peut publier. Lecteur consulte." },
  { q: "Nombre max de visuels recommandé par page ?", o: ["2-3", "10-15", "6-8", "Pas de limite"], a: 2, d: "VA", ch: 7, w: "Max 6-8 visuels par page. Plus = confusion." },
  { q: "Extraction permet de :", o: ["Filtrer tous les visuels", "Créer des relations", "Exporter en PDF", "Naviguer vers une page de détail contextuel"], a: 3, d: "VA", ch: 7, w: "Clic droit → page dédiée avec le contexte de l'élément cliqué." },
  { q: "Signets (Bookmarks) dans Power BI servent à :", o: ["Sauvegarder des états de page pour navigation", "Marquer des favoris", "Créer des rapports", "Filtrer par utilisateur"], a: 0, d: "VA", ch: 7, w: "Sauvegardent un état. Associés à des boutons pour navigation non-linéaire." },
  { q: "PPU vs Pro — différence principale ?", o: ["Prix", "48 refresh/jour au lieu de 8", "Fonctionnalités identiques", "PPU est gratuit"], a: 1, d: "DE", ch: 7, w: "PPU = Premium Per User. 48 refresh/jour, fonctionnalités Premium." },
  { q: "Mise en forme conditionnelle (MFC) fonctionne sur :", o: ["Tous les visuels", "Histogrammes uniquement", "Tableaux et matrices uniquement", "Cartes uniquement"], a: 2, d: "VA", ch: 7, w: "MFC (échelle couleurs, règles, barres) = tableaux et matrices." },
  { q: "Ordre des workspace roles (du plus au moins de droits) ?", o: ["Tous égaux", "Admin > Contributeur > Membre > Lecteur", "Lecteur > Contributeur > Admin", "Admin > Membre > Contributeur > Lecteur"], a: 3, d: "DE", ch: 7, w: "Admin > Membre > Contributeur > Lecteur." },

  // ══════════════════════════════════════════════════════════
  // NOUVELLES QUESTIONS (130+) — PQ / MO / VA / DE
  // ══════════════════════════════════════════════════════════

  // ─── PQ — Préparer les données (~35 questions) ─── Ch.2
  { q: "Un fichier CSV utilise le séparateur point-virgule (;) mais Power Query attend la virgule (,). Que faire ?", o: ["Changer le délimiteur dans les paramètres de la source PQ", "Modifier le CSV dans Excel", "Utiliser DAX pour séparer", "Créer une colonne calculée"], a: 0, d: "PQ", ch: 2, w: "Dans PQ, lors de la connexion CSV, on peut spécifier le délimiteur dans les paramètres de la source." },
  { q: "Quelle est la différence entre 'Supprimer les lignes' et 'Filtrer' dans Power Query ?", o: ["Aucune différence", "Les deux sont réversibles via les étapes appliquées", "Supprimer = permanent, Filtrer = réversible", "Filtrer est plus rapide"], a: 1, d: "PQ", ch: 2, w: "Dans PQ, TOUTES les transformations sont des étapes appliquées, donc réversibles. Les deux approches sont équivalentes." },
  { q: "Un analyste charge 50 colonnes mais n'en utilise que 8. Quel impact ?", o: ["Aucun impact", "Erreurs de calcul", "Modèle plus lourd, plus lent, plus confus", "Power BI refuse de charger"], a: 2, d: "PQ", ch: 2, w: "Chaque colonne inutile augmente la taille du modèle et ralentit les performances. Supprimer tôt dans PQ." },
  { q: "Quelle fonction M permet de filtrer les lignes d'une table ?", o: ["Table.Filter", "Table.RemoveRows", "Table.Where", "Table.SelectRows"], a: 3, d: "PQ", ch: 2, w: "Table.SelectRows(table, each [condition]) est la fonction M pour filtrer les lignes." },
  { q: "Comment combiner 12 fichiers Excel mensuels (même structure) en une seule table ?", o: ["Combiner à partir d'un dossier", "Append Queries (empiler)", "12 Merge Queries", "Importer un par un"], a: 0, d: "PQ", ch: 2, w: "Append empile les lignes. Pour un dossier entier, 'Combiner à partir d'un dossier' est encore mieux." },
  { q: "Après un changement de type, PQ affiche des erreurs sur certaines lignes. Pourquoi ?", o: ["Bug de PQ", "Des valeurs ne sont pas convertibles (ex: texte → nombre)", "Le fichier est corrompu", "Il faut redémarrer Desktop"], a: 1, d: "PQ", ch: 2, w: "Si une cellule contient 'N/A' et qu'on convertit en nombre, PQ génère une erreur pour cette ligne." },
  { q: "Quelle transformation PQ permet de passer de colonnes Jan/Fév/Mar à une colonne Mois + une colonne Valeur ?", o: ["Pivot", "Split", "Unpivot", "Merge"], a: 2, d: "PQ", ch: 2, w: "Unpivot transforme des colonnes en lignes. Pivot fait l'inverse (lignes → colonnes)." },
  { q: "Un analyste veut séparer 'Jean Dupont' en 2 colonnes (Prénom, Nom). Quelle transformation ?", o: ["Colonne conditionnelle", "Remplacer valeurs", "Merge Queries", "Split par délimiteur (espace)"], a: 3, d: "PQ", ch: 2, w: "Split Column by Delimiter (espace) sépare en 2 colonnes." },
  { q: "Que fait Table.TransformColumnTypes en M ?", o: ["Change les types de données", "Renomme les colonnes", "Filtre les lignes", "Trie la table"], a: 0, d: "PQ", ch: 2, w: "Table.TransformColumnTypes change les types. C'est la première étape appliquée automatiquement par PQ." },
  { q: "Un paramètre de requête PQ permet de :", o: ["Accélérer le chargement", "Rendre une valeur dynamique (ex: chemin fichier, seuil)", "Créer des mesures", "Publier sur le Service"], a: 1, d: "PQ", ch: 2, w: "Les paramètres PQ rendent les requêtes flexibles : changer un chemin, un seuil, un filtre sans modifier le code M." },
  { q: "Quelle est la bonne pratique pour gérer les valeurs NULL dans une colonne texte ?", o: ["Les laisser telles quelles", "Supprimer toutes les lignes avec NULL", "Les remplacer par une valeur explicite ('Non renseigné')", "Convertir en nombre 0"], a: 2, d: "PQ", ch: 2, w: "Remplacer par 'Non renseigné' pour que les visuels soient clairs. Supprimer = perte de données." },
  { q: "Quelle différence entre 'Charger' et 'Transformer les données' lors de la connexion ?", o: ["Aucune", "'Charger' est obligatoire pour PostgreSQL", "'Transformer' est plus lent", "'Charger' charge directement, 'Transformer' ouvre PQ d'abord"], a: 3, d: "PQ", ch: 2, w: "Toujours choisir 'Transformer les données' pour vérifier et nettoyer AVANT de charger dans le modèle. Valable pour toutes les sources : PostgreSQL, CSV, Excel, SQL Server." },
  { q: "Un Merge Left Outer retourne :", o: ["Toutes les lignes de la table gauche + correspondances de la droite", "Uniquement les lignes en commun", "Toutes les lignes des deux tables", "Les lignes sans correspondance"], a: 0, d: "PQ", ch: 2, w: "Left Outer = toutes les lignes gauche + correspondances droite (NULL si pas de match). Comme LEFT JOIN en SQL." },
  { q: "Que fait 'Utiliser la première ligne comme en-tête' dans PQ ?", o: ["Supprime la première ligne", "Promeut la première ligne en noms de colonnes", "Filtre les doublons", "Change les types"], a: 1, d: "PQ", ch: 2, w: "Transforme la première ligne de données en noms de colonnes. Utile quand les en-têtes sont dans les données." },
  { q: "Comment créer une colonne avec la logique IF/ELSE dans Power Query ?", o: ["Colonne calculée DAX", "SWITCH en M", "Colonne conditionnelle PQ", "Impossible dans PQ"], a: 2, d: "PQ", ch: 2, w: "Ajouter colonne → Colonne conditionnelle. En M : if [col] > seuil then ... else ..." },
  { q: "Un fichier Excel a des données utiles à partir de la ligne 5. Comment ignorer les 4 premières ?", o: ["Impossible", "Modifier le fichier Excel", "Utiliser un filtre", "Supprimer les premières lignes dans PQ"], a: 3, d: "PQ", ch: 2, w: "Accueil → Supprimer les lignes → Supprimer les N premières lignes (4)." },
  { q: "Quelle est l'étape M générée quand on renomme une colonne ?", o: ["Table.RenameColumns", "Table.TransformColumns", "Table.ChangeNames", "Column.Rename"], a: 0, d: "PQ", ch: 2, w: "Table.RenameColumns(Source, {{\"OldName\", \"NewName\"}})." },
  { q: "Un analyste doit extraire l'année d'une colonne Date dans PQ. Méthode ?", o: ["Créer une mesure DAX YEAR()", "Ajouter colonne → Date → Année dans PQ", "Écrire du SQL", "Impossible dans PQ"], a: 1, d: "PQ", ch: 2, w: "Ajouter colonne → Date → Année (ou Mois, Trimestre, Jour de la semaine)." },
  { q: "Quels types de jointure sont disponibles dans Merge Queries ?", o: ["Seulement Inner Join", "Left et Right uniquement", "Left Outer, Right Outer, Full Outer, Inner, Left Anti, Right Anti", "Inner et Full uniquement"], a: 2, d: "PQ", ch: 2, w: "PQ offre 6 types de jointure, comme SQL. Left Outer est le plus courant (95% des cas)." },
  { q: "Un collègue modifie une étape au milieu du pipeline PQ. Quel risque ?", o: ["Aucun", "Le fichier source est modifié", "PQ refuse la modification", "Les étapes suivantes peuvent casser si elles dépendent de la colonne modifiée"], a: 3, d: "PQ", ch: 2, w: "Les étapes sont séquentielles. Modifier une étape intermédiaire peut casser les suivantes (ex: renommer une colonne utilisée plus loin)." },
  { q: "Comment dupliquer une requête PQ ?", o: ["Clic droit sur la requête → Dupliquer", "Copier-coller dans l'éditeur", "Impossible", "Exporter puis importer"], a: 0, d: "PQ", ch: 2, w: "Clic droit → Dupliquer crée une copie indépendante. Référence crée une dépendance." },
  { q: "Quelle différence entre Dupliquer et Référencer une requête PQ ?", o: ["Identiques", "Dupliquer = copie indépendante, Référencer = dépend de la source", "Référencer est plus rapide", "Dupliquer ne garde pas les étapes"], a: 1, d: "PQ", ch: 2, w: "Dupliquer = copie complète indépendante. Référencer = nouvelle requête qui POINTE vers la première (modification de la source = cascade)." },
  { q: "Un rapport Power BI doit se connecter à une base SQL Server. Quel mode de connectivité choisir pour de petits volumes ?", o: ["DirectQuery", "Live Connection", "Import", "Composite"], a: 2, d: "PQ", ch: 2, w: "Import charge les données en mémoire. Idéal pour < 1 Go. DirectQuery interroge la source à chaque interaction (grands volumes)." },
  { q: "Quels sont les 2 avantages principaux du mode Import vs DirectQuery ?", o: ["Données en temps réel + sécurité", "Gratuit + simple", "Taille illimitée + pas de Gateway", "Performance optimale + DAX complet"], a: 3, d: "PQ", ch: 2, w: "Import : données en cache = ultra rapide, et toutes les fonctions DAX sont disponibles. DirectQuery a des limitations DAX." },
  { q: "Power Query peut-il se connecter à une API REST ?", o: ["Oui, via Web.Contents en M", "Non", "Seulement avec Python", "Seulement en Premium"], a: 0, d: "PQ", ch: 2, w: "Web.Contents(url) en M permet de se connecter à des API REST. On parse ensuite le JSON avec Json.Document()." },
  { q: "Quelle transformation PQ permet de 'dépivotiser' (colonnes → lignes) ?", o: ["Transpose", "Unpivot Columns", "Pivot Column", "Group By"], a: 1, d: "PQ", ch: 2, w: "Unpivot = colonnes → lignes. Pivot = lignes → colonnes. Transpose = rotation complète de la table." },
  { q: "Que signifie 'Query Folding' dans Power Query ?", o: ["Compression des données", "Regroupement de requêtes", "Les transformations PQ sont traduites en requêtes natives (SQL) exécutées à la source", "Sauvegarde automatique"], a: 2, d: "PQ", ch: 2, w: "Query Folding = PQ pousse les transformations vers la source (ex: SQL Server exécute le filtre). Beaucoup plus performant." },
  { q: "Comment vérifier si le Query Folding est actif sur une étape PQ ?", o: ["Regarder le temps de chargement", "Impossible à vérifier", "Vérifier dans le Service", "Clic droit sur l'étape → 'Afficher la requête native'"], a: 3, d: "PQ", ch: 2, w: "Si 'Afficher la requête native' est grisé, le Query Folding est cassé à cette étape." },
  { q: "Quelles transformations PQ cassent généralement le Query Folding ?", o: ["Colonnes personnalisées complexes et Merge entre sources différentes", "Filtrer et trier", "Renommer les colonnes", "Changer les types"], a: 0, d: "PQ", ch: 2, w: "Les colonnes personnalisées avec logique M complexe et les Merge entre sources hétérogènes cassent le folding." },
  { q: "Un analyste doit regrouper les ventes par pays et calculer le total. Quelle transformation PQ ?", o: ["Merge", "Group By (Regrouper)", "Pivot", "Append"], a: 1, d: "PQ", ch: 2, w: "Group By = GROUP BY en SQL. Regroupe les lignes par une ou plusieurs colonnes et applique une agrégation." },
  { q: "Comment gérer les erreurs dans une colonne PQ ?", o: ["Les ignorer", "Supprimer toute la colonne", "Clic droit → Supprimer les erreurs ou Remplacer les erreurs", "Changer le type"], a: 2, d: "PQ", ch: 2, w: "Clic droit sur la colonne → Supprimer les erreurs (supprime les lignes) ou Remplacer les erreurs (par une valeur)." },
  { q: "Quel est l'ordre recommandé des transformations dans PQ ?", o: ["Filtrer → Renommer → Types", "Peu importe l'ordre", "Renommer → Types → Supprimer", "Types → Supprimer colonnes → Filtrer → Renommer → Transformer"], a: 3, d: "PQ", ch: 2, w: "Types en premier (évite les erreurs cascade), puis supprimer colonnes inutiles (allège), filtrer, renommer, transformer." },
  { q: "Un fichier Excel a des cellules fusionnées. Que fait PQ lors du chargement ?", o: ["Remplit la première cellule et met NULL dans les autres", "Ignore les cellules fusionnées", "Erreur de chargement", "Duplique la valeur dans chaque cellule"], a: 0, d: "PQ", ch: 2, w: "PQ place la valeur dans la première cellule et NULL dans les suivantes. Utiliser 'Remplir vers le bas' pour corriger." },
  { q: "Que fait la transformation 'Remplir vers le bas' (Fill Down) ?", o: ["Trie les données", "Remplace les cellules vides par la dernière valeur non-vide au-dessus", "Ajoute des lignes", "Supprime les NULL"], a: 1, d: "PQ", ch: 2, w: "Fill Down copie la dernière valeur non-vide vers le bas. Essentiel pour les données issues d'Excel avec cellules fusionnées." },
  { q: "Un rapport doit combiner données de SQL Server et d'un fichier CSV. Où faire la combinaison ?", o: ["Dans SQL Server", "Impossible", "Dans Power Query via Merge ou Append", "En DAX"], a: 2, d: "PQ", ch: 2, w: "PQ peut combiner des sources hétérogènes. C'est sa force : connecter, nettoyer et combiner des données de sources différentes." },

  // ─── MO — Modéliser les données (~40 questions) ─── Ch.3-5
  { q: "Dans un schéma en étoile, où sont stockées les clés étrangères (FK) ?", o: ["Dans les dimensions", "Dans une table séparée", "Dans les deux", "Dans la table de faits"], a: 3, d: "MO", ch: 3, w: "Les FK sont dans la table de faits. Elles pointent vers les PK des dimensions." },
  { q: "Un modèle a Product → Sales ← Customer. Quel schéma ?", o: ["Étoile", "Flocon de neige", "Cascade", "Réseau"], a: 0, d: "MO", ch: 3, w: "Faits au centre (Sales), dimensions autour (Product, Customer) = schéma en étoile." },
  { q: "Quelle est la différence entre un schéma en étoile et en flocon de neige ?", o: ["Identiques", "Le flocon normalise les dimensions (sous-tables)", "L'étoile a plus de tables", "Le flocon est plus performant"], a: 1, d: "MO", ch: 3, w: "Le flocon de neige décompose les dimensions en sous-dimensions (Product → SubCategory → Category). L'étoile est recommandée pour Power BI." },
  { q: "Pourquoi éviter le schéma en flocon de neige dans Power BI ?", o: ["Il n'est pas supporté", "Il coûte plus cher", "Plus de jointures = plus lent et plus complexe pour DAX", "Il est réservé à SQL Server"], a: 2, d: "MO", ch: 3, w: "En étoile, DAX fonctionne de manière optimale. Le flocon ajoute des jointures inutiles et complique les mesures." },
  { q: "Un modèle a une relation Both entre Product et Sales. Quel risque ?", o: ["Aucun", "Obligatoire pour CALCULATE", "Meilleure performance", "Ambiguïtés de filtrage et résultats incorrects possibles"], a: 3, d: "MO", ch: 3, w: "Both = filtrage bidirectionnel. Peut créer des résultats ambigus quand plusieurs chemins existent. Single = recommandé." },
  { q: "Comment créer une table de dates avec CALENDARAUTO() ?", o: ["Nouvelle table DAX : ADDCOLUMNS(CALENDARAUTO(), colonnes)", "Dans Power Query", "Dans le Service", "Avec Python"], a: 0, d: "MO", ch: 3, w: "CALENDARAUTO() détecte les dates min/max du modèle et génère chaque jour. On ajoute Année, Mois, etc. avec ADDCOLUMNS." },
  { q: "Que se passe-t-il si la table de dates a des 'trous' (jours manquants) ?", o: ["Rien", "TOTALYTD et SAMEPERIODLASTYEAR peuvent retourner des résultats incorrects", "Power BI refuse le modèle", "Les visuels affichent des erreurs"], a: 1, d: "MO", ch: 3, w: "Les fonctions Time Intelligence nécessitent une table de dates CONTINUE (chaque jour). Des trous = résultats faux." },
  { q: "Un analyste a 2 tables de dates (OrderDate et ShipDate). Combien de relations actives possibles entre Sales et DateTable ?", o: ["0", "2 actives", "1 seule active (les autres inactives)", "Illimité"], a: 2, d: "MO", ch: 3, w: "UNE seule relation active entre 2 tables. Les autres doivent être inactives et activées avec USERELATIONSHIP." },
  { q: "RLS (Row Level Security) est appliqué à quel niveau ?", o: ["Au niveau du rapport", "Au niveau du visuel", "Au niveau de la page", "Au niveau du dataset dans le Service"], a: 3, d: "MO", ch: 3, w: "RLS filtre les données au niveau du dataset. Les rôles sont créés dans Desktop et assignés dans Service." },
  { q: "Un utilisateur Admin d'un workspace est-il soumis au RLS ?", o: ["Non — Admin/Membre voient toutes les données", "Oui", "Seulement en mode lecture", "Dépend de la licence"], a: 0, d: "MO", ch: 3, w: "Les Admin et Membre du workspace ne sont PAS soumis au RLS. Seuls les Lecteur et Contributeur le sont." },
  { q: "CALCULATE([CA], Category='Bikes', Category='Accessories') retourne :", o: ["CA Bikes + Accessories", "BLANK (aucune ligne ne peut être les 2)", "CA Bikes seulement", "Erreur"], a: 1, d: "MO", ch: 4, w: "2 filtres sur la MÊME colonne dans CALCULATE = intersection (AND). Aucune ligne ne peut être Bikes ET Accessories → BLANK." },
  { q: "Quelle est la différence entre le contexte de filtre et le contexte de ligne ?", o: ["Identiques", "Ligne = segments, Filtre = CALCULATE", "Filtre = filtres actifs sur les colonnes. Ligne = itération dans un itérateur (SUMX, FILTER)", "Ligne uniquement dans les colonnes calculées"], a: 2, d: "MO", ch: 4, w: "Contexte de filtre = ensemble des filtres (segments, visuels, CALCULATE). Contexte de ligne = ligne courante dans un itérateur ou colonne calculée." },
  { q: "CALCULATE([CA], ALL()) — sans argument dans ALL. Résultat ?", o: ["CA du pays actuel", "Identique à ALL(Sales)", "Erreur", "CA total de tout le modèle (tous filtres supprimés)"], a: 3, d: "MO", ch: 4, w: "ALL() sans argument supprime TOUS les filtres de TOUTES les tables du modèle. Résultat = total absolu." },
  { q: "Un analyste écrit CALCULATE([CA], FILTER(ALL(Sales), [CA Total] > 1000)). Problème ?", o: ["FILTER sur ALL(Sales) itère sur TOUTES les lignes — très lent sur une grosse table", "Aucun", "Erreur de syntaxe", "Résultat toujours BLANK"], a: 0, d: "MO", ch: 4, w: "FILTER(ALL(Sales), ...) supprime d'abord les filtres puis itère sur toutes les lignes. Très coûteux en performance." },
  { q: "CALCULATE modifie-t-il le contexte de LIGNE ?", o: ["Oui", "Non — il modifie le contexte de FILTRE. Il fait aussi la context transition", "Oui si utilisé dans SUMX", "Dépend du filtre"], a: 1, d: "MO", ch: 4, w: "CALCULATE modifie le contexte de FILTRE. Mais dans un itérateur, il fait aussi la 'context transition' : le contexte de ligne devient un contexte de filtre." },
  { q: "Qu'est-ce que la 'context transition' en DAX ?", o: ["Le passage de DAX à M", "Le changement de page dans un rapport", "CALCULATE dans un itérateur transforme le contexte de ligne en contexte de filtre", "Le refresh des données"], a: 2, d: "MO", ch: 4, w: "Quand CALCULATE est appelé dans un itérateur (SUMX, FILTER), le contexte de ligne actuel est transformé en filtres équivalents." },
  { q: "REMOVEFILTERS est un alias de quelle fonction ?", o: ["FILTER", "CALCULATE", "ALLEXCEPT", "ALL"], a: 3, d: "MO", ch: 5, w: "REMOVEFILTERS est un alias de ALL introduit pour plus de clarté. Les deux font exactement la même chose." },
  { q: "ALLSELECTED() dans un visuel avec segment Année=2022. Que garde-t-il ?", o: ["Le filtre du segment (2022) et le RLS, supprime les filtres du visuel", "Rien", "Tous les filtres", "Seulement le RLS"], a: 0, d: "MO", ch: 5, w: "ALLSELECTED supprime les filtres du visuel (axes, légendes) mais GARDE les filtres externes (segments, RLS, filtres de page)." },
  { q: "% CA avec ALLSELECTED vs ALL dans un visuel avec segment. Différence ?", o: ["Aucune", "ALL = % sur TOUT le dataset. ALLSELECTED = % sur la sélection du segment", "ALLSELECTED est plus lent", "ALL est déprécié"], a: 1, d: "MO", ch: 5, w: "Avec segment 2022 : ALL → % sur toutes les années. ALLSELECTED → % sur 2022 seulement (le segment est respecté). ALLSELECTED est correct dans 90% des cas." },
  { q: "SUMX(Sales, Sales[orderqty] * RELATED(Product[listprice])) — que fait RELATED ici ?", o: ["Crée une relation", "Filtre les produits", "Accède à une colonne de la dimension liée dans le contexte de ligne", "Erreur"], a: 2, d: "MO", ch: 5, w: "RELATED() navigue de la table de faits vers la dimension via la relation. Permet d'accéder à listprice du produit lié à chaque ligne de Sales." },
  { q: "Quelle différence entre RELATED et RELATEDTABLE ?", o: ["Identiques", "RELATED marche dans les 2 sens", "RELATEDTABLE est déprécié", "RELATED = 1 valeur (N→1). RELATEDTABLE = table de lignes (1→N)"], a: 3, d: "MO", ch: 5, w: "RELATED navigue du côté N vers le côté 1 (retourne 1 valeur). RELATEDTABLE navigue du côté 1 vers N (retourne une table)." },
  { q: "RANKX : quel est le 4e argument ?", o: ["L'ordre (ASC ou DESC)", "L'expression", "La table", "Le type (Dense/Skip)"], a: 0, d: "MO", ch: 5, w: "RANKX(table, expression, [valeur], [ordre], [type]). 4e arg = ASC ou DESC. 5e = Dense ou Skip." },
  { q: "Un visuel affiche le rang de chaque produit. Un segment pays est actif. Le rang change-t-il ?", o: ["Non, RANKX est fixe", "Oui, le contexte de filtre du segment change le CA de chaque produit → le rang change", "Seulement avec ALLSELECTED", "Dépend de ALL"], a: 1, d: "MO", ch: 5, w: "RANKX recalcule le rang selon le contexte actif. Avec segment France, le produit n1 en France peut être différent du n1 global." },
  { q: "AVERAGEX vs AVERAGE — quand utiliser AVERAGEX ?", o: ["Toujours", "AVERAGEX est plus rapide", "Quand le calcul combine plusieurs colonnes ou nécessite RELATED", "Jamais, AVERAGE suffit"], a: 2, d: "MO", ch: 5, w: "AVERAGEX = itérateur. Nécessaire quand l'expression combine colonnes (ex: moyenne de Prix * Qty par ligne)." },
  { q: "COUNTX(Sales, IF(Sales[orderqty] > 5, 1, BLANK())) — que compte cette mesure ?", o: ["Toutes les lignes", "Erreur", "Les lignes avec Qty <= 5", "Les lignes avec Qty > 5"], a: 3, d: "MO", ch: 5, w: "COUNTX ignore les BLANK. Donc cette formule compte uniquement les lignes où Qty > 5." },
  { q: "VALUES(Product[Color]) retourne :", o: ["Les couleurs VISIBLES dans le contexte de filtre actuel", "Toutes les couleurs de la table", "Un nombre", "Une erreur"], a: 0, d: "MO", ch: 5, w: "VALUES retourne les valeurs distinctes VISIBLES dans le contexte de filtre. Si segment = France, retourne les couleurs des produits vendus en France." },
  { q: "HASONEVALUE(Product[Color]) — usage typique ?", o: ["Vérifier les types", "Savoir si le contexte ne contient qu'une seule valeur (ex: dans un segment)", "Compter les couleurs", "Filtrer les produits"], a: 1, d: "MO", ch: 5, w: "HASONEVALUE = TRUE si le contexte ne contient qu'une valeur. Utile pour afficher conditionnellement (IF HASONEVALUE → afficher la valeur, sinon 'Sélectionnez...')." },
  { q: "SELECTEDVALUE(Product[Color], 'Tous') retourne :", o: ["Toujours 'Tous'", "Toutes les couleurs", "La couleur si une seule est sélectionnée, sinon 'Tous'", "Erreur"], a: 2, d: "MO", ch: 5, w: "SELECTEDVALUE retourne la valeur unique si le contexte n'en contient qu'une, sinon la valeur alternative ('Tous')." },
  { q: "ISBLANK([CA N-1]) retourne TRUE quand :", o: ["CA = 0", "Toujours FALSE", "Le filtre est actif", "Il n'y a pas de données pour la période N-1"], a: 3, d: "MO", ch: 5, w: "ISBLANK = TRUE quand la valeur est BLANK (pas de données). Différent de 0 qui est une valeur." },
  { q: "BLANK() vs 0 dans DAX — quelle différence dans un visuel ?", o: ["BLANK = cellule vide dans le visuel. 0 = affiche 0", "Aucune", "0 est plus rapide", "BLANK génère une erreur"], a: 0, d: "MO", ch: 5, w: "BLANK() = pas de valeur → cellule vide. 0 = une valeur qui s'affiche. Utilisez BLANK() pour ne pas polluer les visuels." },
  { q: "Un modèle a Product avec doublons sur productid. Conséquence sur la relation avec Sales ?", o: ["Aucune", "La relation devient N:N au lieu de 1:N", "Power BI refuse la relation", "Les doublons sont ignorés"], a: 1, d: "MO", ch: 3, w: "Des doublons sur la PK de la dimension créent une relation N:N. Solution : supprimer les doublons dans PQ." },
  { q: "Peut-on avoir une mesure dans une table de dimension ?", o: ["Non, uniquement dans les faits", "Seulement en Premium", "Oui, mais c'est une convention de les mettre dans un 'tableau de mesures'", "Oui, mais ça crée des erreurs"], a: 2, d: "MO", ch: 3, w: "Les mesures peuvent être dans n'importe quelle table. Bonne pratique : créer une table vide dédiée ('Mesures' ou '_Mesures')." },
  { q: "Comment créer une table de mesures vide ?", o: ["Impossible", "Service uniquement", "Dans Power Query", "Modélisation → Nouvelle table → _Mesures = ROW('temp', BLANK())"], a: 3, d: "MO", ch: 3, w: "Créer une table DAX vide, puis y déplacer toutes les mesures. Convention de nommage : préfixe _ pour qu'elle apparaisse en premier." },
  { q: "CALCULATE([CA], DateTable[Année] = 2022, DateTable[Mois] = 3). Combien de filtres et quel comportement ?", o: ["2 filtres, AND (intersection)", "2 filtres, OR", "1 filtre combiné", "Erreur"], a: 0, d: "MO", ch: 4, w: "Plusieurs filtres dans CALCULATE = intersection (AND). Ici : année 2022 ET mois 3 = mars 2022." },
  { q: "CALCULATE([CA], FILTER(Product, Product[listprice] > [Panier Moyen])). Pourquoi FILTER est nécessaire ici ?", o: ["Plus rapide", "Le filtre compare une colonne à une MESURE — impossible en filtre direct", "Obligatoire avec Product", "Pour le Query Folding"], a: 1, d: "MO", ch: 4, w: "Un filtre direct dans CALCULATE ne peut utiliser qu'une colonne vs une valeur constante. Pour comparer à une mesure → FILTER obligatoire." },
  { q: "CALCULATE([CA]) sans aucun filtre — utile ?", o: ["Non, identique à [CA]", "Oui — dans un itérateur, ça déclenche la context transition", "Erreur", "Plus rapide que [CA]"], a: 1, d: "MO", ch: 4, w: "Dans un itérateur (SUMX, FILTER), CALCULATE sans filtre déclenche la context transition : le contexte de ligne devient un contexte de filtre." },
  { q: "Un analyste veut le CA des produits dont le prix est entre 100 et 500. Quelle approche ?", o: ["CALCULATE([CA], Price >= 100, Price <= 500)", "CALCULATE([CA], FILTER(Product, Price >= 100 && Price <= 500))", "Les deux fonctionnent", "Aucune ne fonctionne"], a: 2, d: "MO", ch: 4, w: "Les deux approches sont valides. Les filtres directs (option A) sont traduits en FILTER implicitement. L'option B est plus explicite." },
  { q: "TREATAS(VALUES(DateTable[Année]), DimBudget[Année]) sert à :", o: ["Appliquer un filtre virtuel comme s'il y avait une relation", "Créer une relation", "Changer les types", "Fusionner les tables"], a: 0, d: "MO", ch: 4, w: "TREATAS crée une relation virtuelle dans CALCULATE. Utile quand 2 tables ont la même colonne mais pas de relation physique." },
  { q: "Quelle fonction DAX permet de créer une table virtuelle avec des colonnes spécifiques ?", o: ["TABLE", "SUMMARIZE ou ADDCOLUMNS", "CREATE", "NEWTABLE"], a: 1, d: "MO", ch: 5, w: "SUMMARIZE regroupe + agrège. ADDCOLUMNS ajoute des colonnes calculées à une table existante. Les deux créent des tables virtuelles." },
  { q: "SUMMARIZE(Sales, Product[productsubcategoryid], 'Total', [CA Total]) — que retourne cette expression ?", o: ["Toutes les ventes", "Un nombre", "Une table avec Category et le CA Total par catégorie", "Une erreur car mesure dans SUMMARIZE"], a: 2, d: "MO", ch: 5, w: "SUMMARIZE regroupe par Category et ajoute une colonne calculée 'Total'. Note : Microsoft recommande SUMMARIZECOLUMNS pour les nouveaux développements." },

  // ─── VA — Visualiser et analyser (~30 questions) ─── Ch.6
  { q: "DATESYTD vs TOTALYTD — quelle différence fonctionnelle ?", o: ["DATESYTD est plus rapide", "Aucune — TOTALYTD est un raccourci de CALCULATE + DATESYTD", "TOTALYTD gère l'année fiscale, pas DATESYTD", "Les deux gèrent l'année fiscale"], a: 3, d: "VA", ch: 6, w: "Les deux supportent l'année fiscale en 3e argument. TOTALYTD = CALCULATE([mesure], DATESYTD(Date[Date], '06/30'))." },
  { q: "DATESBETWEEN(DateTable[Date], DATE(2022,1,1), DATE(2022,12,31)) retourne :", o: ["Une table de toutes les dates entre le 1er jan et le 31 déc 2022", "Un nombre de jours", "BLANK", "Erreur"], a: 0, d: "VA", ch: 6, w: "DATESBETWEEN retourne une table de dates filtrée entre 2 bornes. Utile pour des périodes personnalisées." },
  { q: "Un analyste veut le CA des 3 derniers mois glissants. Quelle fonction ?", o: ["TOTALYTD", "DATESINPERIOD(DateTable[Date], MAX(DateTable[Date]), -3, MONTH)", "SAMEPERIODLASTYEAR", "DATEADD"], a: 1, d: "VA", ch: 6, w: "DATESINPERIOD retourne une table de dates couvrant les N dernières unités. Idéal pour les moyennes mobiles." },
  { q: "PARALLELPERIOD(-1, YEAR) sur mars 2022. Que retourne-t-il ?", o: ["Février 2022", "TOUTE l'année 2021 (jan-déc)", "Mars 2021", "Erreur"], a: 2, d: "VA", ch: 6, w: "PARALLELPERIOD retourne la PÉRIODE COMPLÈTE décalée au même grain. Pour mars → retourne mars 2021 (pas l'année entière). Mais pour un trimestre entier → retourne le trimestre décalé." },
  { q: "FIRSTDATE(DateTable[Date]) dans un contexte filtré sur Q1 2022 retourne :", o: ["01/01/2020 (première date du modèle)", "BLANK", "31/03/2022", "01/01/2022 (première date du trimestre filtré)"], a: 3, d: "VA", ch: 6, w: "FIRSTDATE retourne la première date du contexte de filtre actuel. Si Q1 2022, c'est le 1er janvier 2022." },
  { q: "LASTDATE vs MAX(DateTable[Date]) — différence ?", o: ["LASTDATE retourne une TABLE (1 ligne), MAX retourne un SCALAIRE", "Identiques en pratique", "MAX est déprécié", "LASTDATE est plus rapide"], a: 0, d: "VA", ch: 6, w: "LASTDATE retourne une table (utilisable dans CALCULATE comme filtre). MAX retourne un scalaire (utilisable dans des expressions)." },
  { q: "Comment gérer une année fiscale avril-mars dans TOTALYTD ?", o: ["Impossible", "3e argument : TOTALYTD([CA], Date[Date], '03/31')", "Créer une table dates spéciale", "Paramètre dans le Service"], a: 1, d: "VA", ch: 6, w: "Le 3e argument de TOTALYTD définit la fin de l'année fiscale. '03/31' = année fiscale avril-mars." },
  { q: "Un Graphique en courbes affiche CA et CA N-1 sur le même axe temporel. Comment différencier les 2 lignes ?", o: ["Impossible", "Créer 2 graphiques séparés", "Utiliser 2 mesures (CA Total et CA N-1) dans le même visuel", "Utiliser un segment"], a: 2, d: "VA", ch: 6, w: "Glisser les 2 mesures dans le champ Valeurs du Graphique en courbes. Power BI les affiche en 2 lignes distinctes avec légende." },
  { q: "Un tableau affiche CA YTD. Un segment est sur 'Mars 2022'. Le CA YTD affiche le cumul jan+fev+mar. Si on met le segment sur 'Février' ?", o: ["Même valeur", "Erreur", "BLANK", "CA YTD = jan+fev (2 mois au lieu de 3)"], a: 3, d: "VA", ch: 6, w: "TOTALYTD cumule depuis le 1er janvier jusqu'à la date du contexte. Segment février = jan+fév." },
  { q: "OPENINGBALANCEYEAR([Stock], DateTable[Date]) retourne :", o: ["Le stock au 1er janvier de l'année", "Le stock au 31 décembre", "Le stock moyen", "Erreur"], a: 0, d: "VA", ch: 6, w: "OPENINGBALANCEYEAR retourne la valeur au dernier jour de l'année précédente (= ouverture de l'année courante)." },
  { q: "Quel type de visuel est recommandé pour montrer la répartition d'un total en parts ?", o: ["Graphique en courbes", "Graphique en secteurs ou Anneau", "Nuage de points", "Cascade"], a: 1, d: "VA", ch: 6, w: "Pie/Anneau pour les parts (max 5-6 catégories). Au-delà, utiliser un Histogramme trié." },
  { q: "Quel visuel est le plus adapté pour montrer la contribution de chaque catégorie à un total cumulé ?", o: ["Histogramme", "Graphique en courbes", "Graphique en cascade (cascade)", "Table"], a: 2, d: "VA", ch: 6, w: "Le Graphique en cascade montre comment chaque catégorie contribue positivement ou négativement au total." },
  { q: "Un Nuage de points (nuage de points) nécessite au minimum :", o: ["1 mesure", "1 dimension et 1 mesure", "3 dimensions", "2 mesures (X et Y)"], a: 3, d: "VA", ch: 6, w: "X = une mesure, Y = une mesure, Détails = la dimension qui crée les points. Utile pour corrélations." },
  { q: "Comment afficher une carte géographique dans Power BI ?", o: ["Visuel Map avec colonne Country/City", "Uniquement avec Bing Maps API", "Impossible sans licence Premium", "Seulement en Python"], a: 0, d: "VA", ch: 6, w: "Visuel Map (ou Filled Map) avec un champ géographique (Country, State, City). Power BI utilise Bing Maps." },
  { q: "Un rapport doit être accessible sur mobile. Quelle fonctionnalité utiliser ?", o: ["Créer un rapport séparé", "Vue mobile dans Desktop (mise en page responsive)", "Utiliser uniquement des Cartes", "Publier sur le web"], a: 1, d: "VA", ch: 6, w: "Affichage → Vue mobile permet de réorganiser les visuels pour l'affichage smartphone, sans dupliquer le rapport." },
  { q: "Un Treemap est adapté pour :", o: ["Tendances temporelles", "Corrélations", "Hiérarchies et proportions (catégorie → sous-catégorie)", "KPI uniques"], a: 2, d: "VA", ch: 6, w: "Le Treemap montre les proportions hiérarchiques. La taille des rectangles = la valeur de la mesure." },
  { q: "Comment créer un KPI avec indicateur de tendance ?", o: ["Carte avec mesure", "Jauge", "Graphique en courbes", "Visuel KPI : Indicateur + Axe tendance + Objectif"], a: 3, d: "VA", ch: 6, w: "Le visuel KPI natif affiche la valeur, la tendance dans le temps, et la comparaison avec un objectif." },
  { q: "Un Jauge (jauge) affiche :", o: ["Valeur actuelle vs min/max/objectif", "Tendance temporelle", "Répartition en parts", "Classement"], a: 0, d: "VA", ch: 6, w: "La jauge montre où se situe une valeur par rapport à un minimum, maximum et objectif. Utile pour les taux de réalisation." },
  { q: "Quelle est la différence entre un Dashboard et un Rapport dans le Service ?", o: ["Identiques", "Dashboard = 1 page avec tuiles épinglées de plusieurs rapports. Rapport = pages interactives", "Dashboard est gratuit", "Rapport est plus rapide"], a: 1, d: "VA", ch: 6, w: "Un Dashboard est une vue synthétique : tuiles épinglées depuis différents rapports sur UNE page. Un Rapport = pages interactives créées dans Desktop." },
  { q: "Comment épingler un visuel d'un rapport sur un Dashboard ?", o: ["Glisser-déposer", "Dans les paramètres du visuel", "Survoler le visuel → icône Épingler", "Impossible"], a: 2, d: "VA", ch: 6, w: "En mode lecture dans le Service, survoler le visuel → cliquer l'icône épingle → choisir le Dashboard cible." },
  { q: "Les alertes de données dans le Service fonctionnent sur :", o: ["Tous les visuels", "Les datasets", "Les rapports", "Uniquement les tuiles de Dashboard (Cartes, Jauges, KPI)"], a: 3, d: "VA", ch: 6, w: "Les alertes de données ne fonctionnent que sur les tuiles de Dashboard avec une seule valeur numérique (Cartes, Jauges, KPI)." },
  { q: "Un analyste veut un titre de visuel qui change selon le segment (ex: 'CA France' quand France sélectionné). Comment ?", o: ["Créer une mesure avec SELECTEDVALUE et l'utiliser comme titre conditionnel", "Titre dynamique impossible", "Créer un visuel par pays", "Modifier le titre manuellement"], a: 0, d: "VA", ch: 6, w: "Mesure : Titre = 'CA ' & SELECTEDVALUE(Territory[countryregioncode], 'Tous Pays'). Utiliser cette mesure dans le titre conditionnel du visuel." },
  { q: "Comment synchroniser un segment entre plusieurs pages ?", o: ["Impossible", "Affichage → Synchroniser les segments → sélectionner les pages", "Utiliser le même champ sur chaque page", "Dans le Service"], a: 1, d: "VA", ch: 6, w: "Affichage → Synchroniser les segments. On choisit sur quelles pages le segment est visible et/ou synchro." },
  { q: "Un analyste veut un rapport paginé (facture, relevé). Quel outil ?", o: ["Power BI Desktop", "Excel", "Power BI Report Builder (Paginated Reports)", "Power Query"], a: 2, d: "VA", ch: 6, w: "Les Paginated Reports (Report Builder) sont conçus pour les rapports pixel-perfect : factures, relevés, rapports imprimables." },

  // ─── DE — Déployer et maintenir (~25 questions) ─── Ch.7
  { q: "Un Gateway on-premises est nécessaire quand :", o: ["Toujours", "On utilise DirectQuery", "La source est dans Azure", "La source de données est locale (SQL Server, fichiers réseau)"], a: 3, d: "DE", ch: 7, w: "Le Gateway fait le pont entre le cloud (Service) et les sources locales. Pas nécessaire pour les sources cloud (Azure SQL, SharePoint Online)." },
  { q: "Quelle est la différence entre Gateway personnel et Enterprise ?", o: ["Personnel = 1 utilisateur, pas de gestion centralisée. Enterprise = partagé, géré par IT", "Identiques", "Enterprise est gratuit", "Personnel est plus sécurisé"], a: 0, d: "DE", ch: 7, w: "Personal = installé et géré par 1 personne. Enterprise = géré par l'IT, partagé entre utilisateurs, recommandé en production." },
  { q: "Le mode d'actualisation 'Incremental Refresh' permet de :", o: ["Actualiser toutes les données à chaque refresh", "Actualiser plus vite en ne rechargeant que les nouvelles données", "Supprimer les anciennes données", "Changer le mode de connexion"], a: 1, d: "DE", ch: 7, w: "Incremental Refresh ne recharge que les données nouvelles/modifiées. Beaucoup plus rapide pour les grands volumes." },
  { q: "Combien de datasets un workspace Pro peut-il contenir ?", o: ["10", "1 000", "Illimité (dans la limite de 10 Go par dataset)", "Dépend du nombre d'utilisateurs"], a: 2, d: "DE", ch: 7, w: "Pas de limite stricte sur le nombre de datasets. La limite est sur la TAILLE : 1 Go par dataset en Pro, 10 Go en PPU/Premium." },
  { q: "Quelle est la taille max d'un dataset en mode Import avec licence Pro ?", o: ["100 Mo", "Illimité", "10 Go", "1 Go"], a: 3, d: "DE", ch: 7, w: "Pro = 1 Go par dataset. PPU/Premium = jusqu'à 10 Go (configurable)." },
  { q: "Un rapport publié affiche des données obsolètes. Première vérification ?", o: ["Vérifier la dernière actualisation planifiée dans les paramètres du dataset", "Republier le rapport", "Contacter le support Microsoft", "Changer de licence"], a: 0, d: "DE", ch: 7, w: "Dataset → Paramètres → Historique d'actualisation. Vérifier si le refresh a échoué (souvent : credentials expirés)." },
  { q: "Comment partager un rapport avec des utilisateurs externes (hors organisation) ?", o: ["Impossible", "Azure AD B2B + licence Guest", "Envoyer le fichier .pbix", "Publier sur le web"], a: 1, d: "DE", ch: 7, w: "Azure AD B2B permet d'inviter des guests. 'Publier sur le web' n'a AUCUNE sécurité — jamais pour des données d'entreprise." },
  { q: "Un Deployment Pipeline sert à :", o: ["Déployer des rapports en production", "Créer des rapports automatiquement", "Gérer les versions Dev → Test → Production des rapports", "Sauvegarder les données"], a: 2, d: "DE", ch: 7, w: "Deployment Pipeline = promotion contrôlée entre environnements. Dev → Test → Prod avec comparaison des changements." },
  { q: "Comment configurer un refresh automatique quotidien à 6h du matin ?", o: ["Dans Desktop", "Dans le Gateway", "Avec Power Automate", "Service → Dataset → Paramètres → Actualisation planifiée"], a: 3, d: "DE", ch: 7, w: "Dans le Service : Dataset → Paramètres → Actualisation planifiée → Activer → Définir l'heure (06:00)." },
  { q: "Un dataset est actualisé 9 fois par jour avec licence Pro. Résultat ?", o: ["La 9e actualisation est refusée (max 8/jour en Pro)", "Tout fonctionne", "Le dataset est supprimé", "Upgrade automatique en PPU"], a: 0, d: "DE", ch: 7, w: "Pro = max 8 actualisations planifiées/jour. La 9e échoue. Pour plus → PPU (48/jour) ou Premium." },
  { q: "Quelle est la différence entre une Application Power BI et un Workspace ?", o: ["Identiques", "Une App = version packagée et publiée d'un workspace pour les utilisateurs finaux", "App est gratuite, Workspace est Pro", "Workspace est dans Desktop"], a: 1, d: "DE", ch: 7, w: "L'App est un package distribué aux consommateurs. Le Workspace est l'espace de travail des créateurs. L'App est mise à jour quand on la republie." },
  { q: "Un Lecteur de workspace peut-il modifier un rapport ?", o: ["Oui", "Seulement les visuels", "Non — consultation uniquement", "Seulement avec PBIX"], a: 2, d: "DE", ch: 7, w: "Lecteur = lecture seule. Contributeur = peut modifier et publier. Membre = Contributeur + gérer les datasets. Admin = tout." },
  { q: "Comment empêcher un utilisateur de télécharger les données d'un rapport ?", o: ["Utiliser DirectQuery", "Paramètres du dataset → Désactiver l'export", "Supprimer les tables du modèle", "Impossible"], a: 3, d: "DE", ch: 7, w: "Certains paramètres de tenant/workspace permettent de contrôler l'export. En pratique, c'est géré par l'admin Power BI." },
  { q: "Un analyste publie un rapport avec RLS. Les lecteurs voient toutes les données. Diagnostic ?", o: ["Les rôles RLS ne sont pas ASSIGNÉS dans le Service", "RLS non supporté en Pro", "Le modèle est incorrect", "Les lecteurs sont Admin"], a: 0, d: "DE", ch: 7, w: "RLS : créer dans Desktop + ASSIGNER dans le Service. Sans assignation, les rôles existent mais ne filtrent rien." },
  { q: "Qu'est-ce que la fonctionnalité 'Sensitivity Labels' (étiquettes de confidentialité) ?", o: ["Des labels visuels", "Des classifications de sécurité (Public, Confidentiel, Très confidentiel) appliquées aux rapports/datasets", "Des filtres automatiques", "Des licences"], a: 1, d: "DE", ch: 7, w: "Les Sensitivity Labels classifient les contenus Power BI et peuvent contrôler l'export, le partage et la protection." },
  { q: "DirectQuery vs Import — quel mode permet d'utiliser TOUTES les fonctions DAX ?", o: ["DirectQuery", "Les deux", "Import", "Aucun"], a: 2, d: "DE", ch: 7, w: "En Import, toutes les fonctions DAX sont disponibles. En DirectQuery, certaines fonctions sont limitées car les calculs sont traduits en SQL." },
  { q: "Qu'est-ce que le mode Composite dans Power BI ?", o: ["Un mode de visualisation", "Un outil de nettoyage", "Un type de licence", "Un modèle qui combine Import et DirectQuery sur différentes tables"], a: 3, d: "DE", ch: 7, w: "Le mode Composite permet d'avoir certaines tables en Import (rapide) et d'autres en DirectQuery (temps réel). Flexibilité maximale." },
  { q: "Comment versionner un fichier .pbix ?", o: ["Utiliser Git ou SharePoint avec versioning", "Power BI gère automatiquement les versions", "Impossible", "Dans le Service uniquement"], a: 0, d: "DE", ch: 7, w: "Le .pbix est un fichier binaire. Git (avec .gitignore pour les grands fichiers) ou SharePoint avec versioning sont les solutions courantes." },
  { q: "Qu'est-ce qu'un Dataflow dans Power BI ?", o: ["Un type de visuel", "Un ETL dans le cloud (PQ dans le Service) réutilisable entre rapports", "Un type de licence", "Un outil de déploiement"], a: 1, d: "DE", ch: 7, w: "Un Dataflow = Power Query dans le Service. Les transformations sont centralisées et réutilisables par plusieurs rapports. Nécessite PPU ou Premium." },
  { q: "Un admin veut auditer qui consulte quels rapports. Quel outil ?", o: ["Power Query", "Desktop", "Power BI Activity Log / Audit Log dans Microsoft 365", "Gateway"], a: 2, d: "DE", ch: 7, w: "L'Activity Log (Service) ou l'Audit Log (Microsoft 365) tracent toutes les activités : consultation, export, partage, refresh." },
  { q: "Quelle API permet d'automatiser la gestion de Power BI (créer workspaces, refresh, etc.) ?", o: ["Power Query API", "M API", "DAX API", "Power BI REST API"], a: 3, d: "DE", ch: 7, w: "La Power BI REST API permet d'automatiser : refresh de datasets, gestion des workspaces, export de rapports, etc." },
  { q: "Un rapport Power BI doit être intégré dans une application web interne. Quelle approche ?", o: ["Power BI Embedded (embed token + iframe)", "Publier sur le web", "Exporter en PDF", "Partager le lien"], a: 0, d: "DE", ch: 7, w: "Power BI Embedded permet d'intégrer des rapports dans des apps web avec contrôle d'accès. 'Publier sur le web' = AUCUNE sécurité." },
  { q: "Quelle est la différence entre 'Publier sur le web' et 'Incorporer dans SharePoint' ?", o: ["Identiques", "'Publier sur le web' = public sans sécurité. SharePoint = dans le tenant avec authentification", "SharePoint est plus lent", "Publier sur le web est réservé aux Admin"], a: 1, d: "DE", ch: 7, w: "'Publier sur le web' = lien public, 0 sécurité. 'Incorporer dans SharePoint' = intégration dans l'intranet avec authentification Azure AD." },
  { q: "Comment configurer les credentials d'une source de données dans le Service ?", o: ["Dans Desktop", "Dans le Gateway", "Dataset → Paramètres → Informations d'identification de la source de données", "Automatique"], a: 2, d: "DE", ch: 7, w: "Les credentials sont configurées dans le Service pour que le refresh planifié puisse accéder à la source." },

  // ─── Questions multi-réponses (type: 'multi') ───
  { q: "Quels sont les prérequis d'une table de dates pour la Time Intelligence ? (2 réponses)", o: ["Table continue (chaque jour)", "Relation avec la table Product", "Marquée comme table de dates", "Contenir au moins 5 ans"], a: [0, 2], type: "multi", d: "MO", ch: 3, w: "Les 3 prérequis sont : continue (chaque jour), marquée, relation active. Les 2 obligatoires testés ici sont la continuité et le marquage." },
  { q: "Quelles fonctions suppriment des filtres dans CALCULATE ? (2 réponses)", o: ["FILTER", "ALL", "KEEPFILTERS", "REMOVEFILTERS"], a: [1, 3], type: "multi", d: "MO", ch: 5, w: "ALL et REMOVEFILTERS (alias de ALL) suppriment des filtres. FILTER ajoute un filtre. KEEPFILTERS force l'intersection." },
  { q: "Quels rôles de workspace permettent de publier un rapport ? (2 réponses)", o: ["Lecteur", "Contributeur", "Admin", "Viewer"], a: [1, 2], type: "multi", d: "DE", ch: 7, w: "Contributeur et Admin (et Membre) peuvent publier. Lecteur ne peut que consulter." },
  { q: "Quels sont les avantages de VAR/RETURN en DAX ? (2 réponses)", o: ["Code plus lisible et structuré", "Permet de modifier les données source", "Variable évaluée une seule fois (performance)", "Obligatoire pour CALCULATE"], a: [0, 2], type: "multi", d: "MO", ch: 5, w: "VAR rend le code lisible et chaque variable n'est évaluée qu'une fois (pas de recalcul)." },
  { q: "Quelles mesures Time Intelligence nécessitent une table de dates marquée ? (2 réponses)", o: ["SUM", "TOTALYTD", "COUNTROWS", "SAMEPERIODLASTYEAR"], a: [1, 3], type: "multi", d: "VA", ch: 6, w: "Toutes les fonctions Time Intelligence (TOTALYTD, SAMEPERIODLASTYEAR, DATEADD, etc.) nécessitent une table de dates marquée." },
  { q: "Quelles licences Power BI permettent l'actualisation planifiée ? (2 réponses)", o: ["Free", "Pro", "Premium Per User (PPU)", "Desktop"], a: [1, 2], type: "multi", d: "DE", ch: 7, w: "Pro (8/jour) et PPU (48/jour) supportent l'actualisation planifiée. Free ne permet pas de planifier." },
  { q: "Quels itérateurs DAX existent dans cette liste ? (2 réponses)", o: ["CALCULATE", "SUMX", "ALL", "AVERAGEX"], a: [1, 3], type: "multi", d: "MO", ch: 5, w: "SUMX et AVERAGEX sont des itérateurs (parcourent ligne par ligne). CALCULATE modifie le contexte. ALL supprime les filtres." },
  { q: "Quels visuels sont adaptés pour afficher un KPI unique ? (2 réponses)", o: ["Carte", "Graphique en courbes", "Jauge", "Nuage de points"], a: [0, 2], type: "multi", d: "VA", ch: 7, w: "Carte = chiffre unique. Jauge = chiffre avec min/max/objectif. Les deux affichent un KPI." },
  { q: "Quelles approches permettent de créer un RLS dynamique ? (2 réponses)", o: ["Rôle fixe par pays", "USERNAME() ou USERPRINCIPALNAME() dans le filtre RLS", "Table de sécurité avec mapping utilisateur-filtre", "Créer un workspace par utilisateur"], a: [1, 2], type: "multi", d: "DE", ch: 7, w: "RLS dynamique : utiliser USERNAME() pour identifier l'utilisateur, ou une table de sécurité qui mappe les utilisateurs à leurs filtres." },
  { q: "Quelles sont les 2 composantes du contexte d'évaluation en DAX ? (2 réponses)", o: ["Contexte de filtre", "Contexte de modèle", "Contexte de ligne", "Contexte de page"], a: [0, 2], type: "multi", d: "MO", ch: 4, w: "DAX a 2 contextes : le contexte de filtre (filtres actifs) et le contexte de ligne (ligne courante dans un itérateur ou colonne calculée)." },

  // ─── Questions d'ordonnancement (type: 'order') ───
  { q: "Dans quel ordre effectuer ces étapes dans Power Query ?", o: ["Renommer les colonnes", "Vérifier les types de données", "Supprimer les colonnes inutiles", "Filtrer les lignes invalides"], a: [1, 2, 3, 0], type: "order", d: "PQ", ch: 2, w: "Types d'abord (erreurs en cascade sinon) → Supprimer colonnes (allège) → Filtrer lignes → Renommer (cosmétique)." },
  { q: "Dans quel ordre construire un rapport Power BI ?", o: ["Créer les visuels", "Connecter et nettoyer les données (PQ)", "Publier sur le Service", "Créer le modèle et les mesures DAX"], a: [1, 3, 0, 2], type: "order", d: "DE", ch: 7, w: "Données (PQ) → Modèle (relations + DAX) → Visuels → Publication. Toujours dans cet ordre." },
  { q: "Dans quel ordre configurer la sécurité RLS ?", o: ["Assigner les utilisateurs dans le Service", "Tester avec 'Afficher en tant que' dans Desktop", "Créer les rôles dans Desktop", "Publier le rapport"], a: [2, 1, 3, 0], type: "order", d: "DE", ch: 7, w: "Créer rôles → Tester en local → Publier → Assigner dans Service." },
  { q: "Ordre des étapes pour créer une mesure Time Intelligence YTD ?", o: ["Écrire TOTALYTD([CA], DateTable[Date])", "Marquer la table comme table de dates", "Créer la relation DateTable → Sales", "Créer la table de dates (CALENDARAUTO)"], a: [3, 2, 1, 0], type: "order", d: "VA", ch: 6, w: "Créer table dates → Relation → Marquer → Écrire la mesure. Les prérequis d'abord !" },
  { q: "Ordre de résolution du contexte de filtre dans Power BI ?", o: ["Filtres de page/rapport", "CALCULATE (modifications DAX)", "RLS (sécurité)", "Segments et axes du visuel"], a: [2, 0, 3, 1], type: "order", d: "MO", ch: 4, w: "RLS d'abord (sécurité) → Filtres page/rapport → Segments/visuels → CALCULATE modifie le tout en dernier." },

  // ─── Lot supplémentaire — 55 questions pour atteindre 250+ ───

  // PQ supplémentaires
  { q: "Quelle fonction M permet de joindre 2 textes ?", o: ["CONCATENATE", "JOIN", "MERGE", "Text.Combine ou &"], a: 3, d: "PQ", ch: 2, w: "En M : [Col1] & \" \" & [Col2] ou Text.Combine({[Col1], [Col2]}, \" \")." },
  { q: "Comment trier une colonne texte (mois) par une colonne numérique dans PQ ?", o: ["Impossible dans PQ — le tri par colonne se fait dans le modèle Desktop", "Clic droit → Trier", "Utiliser SORT en M", "Supprimer et recréer"], a: 0, d: "PQ", ch: 2, w: "Le tri par colonne (Sort by Column) est une fonctionnalité du modèle, pas de PQ. Dans Desktop : sélectionner la colonne texte → Outils de colonne → Trier par colonne." },
  { q: "Que fait Table.Distinct en M ?", o: ["Trie la table", "Supprime les lignes en doublon", "Compte les valeurs distinctes", "Change les types"], a: 1, d: "PQ", ch: 2, w: "Table.Distinct supprime les doublons. Équivalent de 'Supprimer les doublons' dans l'UI." },
  { q: "Un fichier source CSV change de chemin chaque mois. Comment rendre le chemin dynamique ?", o: ["Modifier le code M manuellement", "Impossible", "Utiliser un paramètre PQ pour le chemin du fichier", "Créer un nouveau rapport"], a: 2, d: "PQ", ch: 2, w: "Les paramètres PQ permettent de rendre dynamiques : chemins, seuils, noms de serveurs. Gérer les paramètres → Nouveau." },
  { q: "Quelle est la bonne pratique pour nommer les requêtes PQ ?", o: ["Garder les noms par défaut", "Noms courts (1-2 lettres)", "Préfixer avec PQ_", "Noms business clairs : 'Ventes', 'Produits', 'Clients'"], a: 3, d: "PQ", ch: 2, w: "Les noms de requêtes deviennent les noms de tables dans le modèle. Des noms business clairs facilitent la lecture pour tous." },
  { q: "Que fait l'opération 'Pivoter la colonne' (Pivot) dans PQ ?", o: ["Transforme des valeurs de lignes en colonnes (inverse d'Unpivot)", "Transforme colonnes en lignes", "Trie les données", "Filtre les doublons"], a: 0, d: "PQ", ch: 2, w: "Pivot = lignes → colonnes (ex: valeurs Jan/Fev/Mar d'une colonne Mois deviennent 3 colonnes). Inverse de Unpivot." },
  { q: "Comment désactiver le chargement d'une requête PQ dans le modèle ?", o: ["Supprimer la requête", "Clic droit sur la requête → Décocher 'Activer le chargement'", "La mettre en commentaire", "Impossible"], a: 1, d: "PQ", ch: 2, w: "Utile pour les tables intermédiaires (staging). La requête reste disponible comme source pour d'autres requêtes mais n'est pas chargée dans le modèle." },
  { q: "Un analyste veut extraire les 3 premiers caractères d'un code produit. Quelle transformation PQ ?", o: ["Colonne conditionnelle", "Filtrer", "Ajouter colonne → Extraire → Premiers caractères (3)", "Split"], a: 2, d: "PQ", ch: 2, w: "Ajouter colonne → À partir du texte → Extraire → Premiers caractères. En M : Text.Start([Code], 3)." },

  // MO supplémentaires
  { q: "Dans CALCULATE, plusieurs filtres sur des colonnes DIFFÉRENTES sont combinés comment ?", o: ["OR", "Erreur", "Le dernier écrase les autres", "AND (intersection)"], a: 3, d: "MO", ch: 4, w: "Colonnes différentes = AND. CALCULATE([CA], Country='France', Year=2022) → France ET 2022." },
  { q: "CALCULATE([CA], VALUES(Product[Color])) — que fait VALUES ici ?", o: ["Retourne les couleurs visibles dans le contexte actuel comme filtre", "Supprime les filtres", "Crée une table", "Erreur"], a: 0, d: "MO", ch: 4, w: "VALUES retourne les valeurs distinctes du contexte. Utilisé dans CALCULATE, il 'fige' les filtres actuels." },
  { q: "Quelle fonction DAX retourne TRUE si une colonne contient plusieurs valeurs dans le contexte ?", o: ["HASONEVALUE", "Les trois existent et ont des usages différents", "ISCROSSFILTERED", "ISFILTERED"], a: 1, d: "MO", ch: 5, w: "HASONEVALUE = TRUE si 1 valeur. ISFILTERED = TRUE si la colonne est filtrée directement. ISCROSSFILTERED = TRUE si filtrée directement ou indirectement." },
  { q: "EARLIER([Col]) dans une colonne calculée — que fait-il ?", o: ["Accède à la valeur précédente", "Retourne la première valeur", "Accède au contexte de ligne EXTERNE (utile dans des calculs imbriqués)", "Erreur"], a: 2, d: "MO", ch: 5, w: "EARLIER accède au contexte de ligne externe dans des expressions imbriquées. Rarement utilisé car VAR est plus lisible." },
  { q: "GENERATEALL vs GENERATE — quelle différence ?", o: ["Identiques", "GENERATEALL est déprécié", "GENERATE est plus rapide", "GENERATEALL garde les lignes sans correspondance (avec BLANK), GENERATE les supprime"], a: 3, d: "MO", ch: 5, w: "GENERATE = CROSS JOIN filtré (supprime les lignes vides). GENERATEALL = garde toutes les lignes (LEFT JOIN)." },
  { q: "CROSSJOIN(Product, Territory) retourne :", o: ["Le produit cartésien de toutes les combinaisons produit × pays", "Une jointure par clé", "Une erreur", "Les lignes en commun"], a: 0, d: "MO", ch: 5, w: "CROSSJOIN = produit cartésien. 300 produits × 6 pays = 1800 lignes. Utile pour les tables de budget avec toutes les combinaisons." },
  { q: "Que fait CALCULATETABLE vs CALCULATE ?", o: ["Identiques", "CALCULATE retourne un scalaire, CALCULATETABLE retourne une TABLE", "CALCULATETABLE est plus rapide", "CALCULATETABLE est déprécié"], a: 1, d: "MO", ch: 4, w: "CALCULATE modifie le contexte et évalue une expression scalaire. CALCULATETABLE modifie le contexte et retourne une table." },
  { q: "Un modèle a 2 tables de faits (Sales et Budget) partageant DateTable. Quel schéma ?", o: ["Étoile simple", "Flocon de neige", "Constellation (ou multi-faits)", "Réseau"], a: 2, d: "MO", ch: 3, w: "Un schéma constellation (ou Galaxy) a plusieurs tables de faits partageant des dimensions communes. Fréquent en BI." },
  { q: "Comment masquer une colonne technique (ex: productid) pour les utilisateurs ?", o: ["La supprimer", "La renommer", "Changer le type", "Clic droit → Masquer dans la vue rapport"], a: 3, d: "MO", ch: 3, w: "Masquer garde la colonne disponible pour les relations et les calculs DAX, mais elle n'apparaît plus dans le panneau Champs pour les créateurs de visuels." },
  { q: "Quelle est la différence entre COUNTBLANK et COUNTA ?", o: ["COUNTBLANK = compte les vides. COUNTA = compte les non-vides", "Identiques", "COUNTA est plus rapide", "COUNTBLANK n'existe pas"], a: 0, d: "MO", ch: 5, w: "COUNTBLANK = nombre de cellules vides/NULL. COUNTA = nombre de cellules NON vides. COUNTBLANK + COUNTA = total de lignes." },
  { q: "ISINSCOPE(DateTable[Année]) — à quoi sert cette fonction ?", o: ["Vérifier si la table existe", "Savoir si la colonne est utilisée comme groupement dans le visuel actuel", "Filtrer par année", "Créer un scope"], a: 1, d: "MO", ch: 5, w: "ISINSCOPE = TRUE si la colonne est dans les axes/groupements du visuel. Utile pour conditionner l'affichage d'une mesure selon le niveau de détail." },
  { q: "Comment forcer un format d'affichage sur une mesure (ex: pourcentage) ?", o: ["FORMAT() dans la mesure", "Impossible", "Sélectionner la mesure → Outils de mesure → Format → Pourcentage", "Dans Power Query"], a: 2, d: "MO", ch: 5, w: "Le format s'applique via Outils de mesure (pas avec FORMAT qui retourne du texte). FORMAT retourne du texte = impossible de faire des calculs dessus." },

  // VA supplémentaires
  { q: "Comment créer un visuel Matrice avec sous-totaux par catégorie ?", o: ["Histogramme", "Impossible", "Table simple", "Visuel Matrice avec lignes hiérarchiques (Catégorie > Sous-catégorie) et activer les sous-totaux"], a: 3, d: "VA", ch: 6, w: "La Matrice est le tableau croisé dynamique de Power BI. Sous-totaux activables dans Format → Sous-totaux." },
  { q: "Un visuel Decomposition Tree sert à :", o: ["Explorer les contributeurs d'une mesure en drillant par différentes dimensions", "Afficher un arbre de décision", "Créer des hiérarchies", "Générer des prévisions"], a: 0, d: "VA", ch: 6, w: "Le Decomposition Tree permet d'explorer interactivement pourquoi une mesure a une certaine valeur en drillant par dimensions." },
  { q: "Comment créer un visuel avec un axe secondaire (2 échelles différentes) ?", o: ["Impossible", "Graphique combiné (Courbes + Histogramme groupé) avec axe secondaire", "2 graphiques empilés", "Segment"], a: 1, d: "VA", ch: 6, w: "Le Graphique combiné permet de combiner barres et lignes avec 2 axes Y (primaire et secondaire). Idéal pour CA + Marge% sur le même visuel." },
  { q: "Smart Narratives dans Power BI permet de :", o: ["Écrire des commentaires manuels", "Créer des rapports paginés", "Générer automatiquement des résumés textuels à partir des données", "Envoyer des emails"], a: 2, d: "VA", ch: 6, w: "Smart Narratives génère un texte descriptif automatique basé sur les données et mesures du rapport." },
  { q: "Comment ajouter une image de fond à une page de rapport ?", o: ["Impossible", "Dans Power Query", "Coller une image", "Format de page → Fond de page → Image"], a: 3, d: "VA", ch: 7, w: "Format → Fond de page → Parcourir → Image. Transparence réglable. Utile pour les arrière-plans corporate ou les wireframes." },
  { q: "Un analyste veut qu'un visuel NE soit PAS filtré par un segment. Comment ?", o: ["Modifier les interactions : sélectionner le segment → Format → Modifier les interactions → icône 'Aucune' sur le visuel", "Impossible", "Supprimer le segment", "Créer une page séparée"], a: 0, d: "VA", ch: 7, w: "Modifier les interactions permet de contrôler quel segment affecte quel visuel. Icône 'Aucune' = pas de filtrage croisé." },
  { q: "Un visuel R ou Python dans Power BI nécessite :", o: ["Une licence Premium", "L'installation du runtime R ou Python sur la machine et sa configuration dans Desktop", "Un serveur dédié", "Power Apps"], a: 1, d: "VA", ch: 7, w: "Les visuels R/Python nécessitent le runtime installé localement. Limitation : ne fonctionnent pas dans le Service (sécurité)." },
  { q: "Comment exporter un rapport Power BI en PDF ?", o: ["Impossible", "Capture d'écran", "Fichier → Exporter → PDF dans Desktop, ou dans le Service : Exporter → PDF", "Power Automate"], a: 2, d: "VA", ch: 7, w: "Export PDF disponible dans Desktop et dans le Service. Chaque page du rapport = une page PDF." },
  { q: "Quelle est la différence entre un filtre de visuel, de page et de rapport ?", o: ["Aucune", "Rapport est optionnel", "Page est plus prioritaire", "Visuel = 1 visuel. Page = tous les visuels de la page. Rapport = toutes les pages"], a: 3, d: "VA", ch: 7, w: "3 niveaux hiérarchiques : Visuel (local à 1 visuel) → Page (tous les visuels de la page) → Rapport (toutes les pages)." },

  // DE supplémentaires
  { q: "Power BI Premium (capacité dédiée) est facturé :", o: ["Par capacité (noeud de calcul), indépendamment du nombre d'utilisateurs", "Par utilisateur", "Gratuit", "Par rapport"], a: 0, d: "DE", ch: 7, w: "Premium par capacité = coût fixe mensuel (~4 995 €/mois pour P1). Tous les utilisateurs (même Free) peuvent consulter. PPU = Premium par utilisateur." },
  { q: "Qu'est-ce que le XMLA endpoint dans Premium ?", o: ["Un format d'export", "Un point d'accès qui permet de connecter des outils tiers (SSMS, Tabular Editor) au dataset", "Un type de licence", "Un protocole réseau"], a: 1, d: "DE", ch: 7, w: "Le XMLA endpoint permet de gérer les datasets avec des outils professionnels comme Tabular Editor ou SQL Server Management Studio." },
  { q: "Comment automatiser l'envoi d'un rapport PDF par email chaque lundi ?", o: ["Manuellement", "Script Python", "Power Automate avec le connecteur Power BI (Export to File + Send Email)", "Impossible"], a: 2, d: "DE", ch: 7, w: "Power Automate peut déclencher un export PDF et l'envoyer par email sur un planning récurrent." },
  { q: "Un dataset utilise des données sensibles (salaires). Quelle protection au-delà du RLS ?", o: ["Aucune protection supplémentaire", "VPN", "Mot de passe sur le .pbix", "Sensitivity Labels + contrôle de l'export + encryption"], a: 3, d: "DE", ch: 7, w: "Sensitivity Labels classifient les données. Combined avec Microsoft Information Protection, elles contrôlent l'export et le partage." },
  { q: "Comment surveiller les performances d'un rapport (visuels lents) ?", o: ["Performance Analyzer dans Desktop (Affichage → Analyseur de performances)", "Impossible", "Chronomètre", "Logs du Service"], a: 0, d: "DE", ch: 7, w: "Performance Analyzer mesure le temps de chaque requête DAX et de chaque visuel. Identifie les visuels lents à optimiser." },
  { q: "DAX Studio est un outil externe qui permet de :", o: ["Créer des visuels", "Déboguer et optimiser les requêtes DAX, analyser les performances du modèle", "Publier sur le Service", "Gérer les licences"], a: 1, d: "DE", ch: 7, w: "DAX Studio = outil gratuit indispensable pour écrire/tester des requêtes DAX, analyser le VertiPaq et optimiser les performances." },
  { q: "Tabular Editor est recommandé pour :", o: ["Créer des visuels", "Remplacer Desktop", "Gérer les mesures en masse, best practices analyzer, déploiement avancé", "Gérer les licences"], a: 2, d: "DE", ch: 7, w: "Tabular Editor permet de gérer les mesures, perspectives, traductions et d'analyser les bonnes pratiques du modèle." },
  { q: "Comment gérer le versioning quand plusieurs analystes travaillent sur le même rapport ?", o: ["Envoyer le .pbix par email", "SharePoint uniquement", "Un seul analyste à la fois", "Utiliser Power BI Projects (.pbip) avec Git ou un workspace de développement"], a: 3, d: "DE", ch: 7, w: "Power BI Projects (.pbip) décompose le .pbix en fichiers texte (JSON, TMDL) versionnables avec Git. Solution moderne recommandée." },

  // Questions finales pour atteindre 250+
  { q: "Un rapport affiche '(Blank)' dans un segment. D'où vient ce problème ?", o: ["Des valeurs NULL dans la colonne source — les remplacer dans PQ", "Bug de Power BI", "Problème de licence", "Le visuel est mal configuré"], a: 0, d: "PQ", ch: 2, w: "Les NULL dans les données apparaissent comme '(Blank)' dans les visuels. Solution : remplacer les NULL dans PQ." },
  { q: "CLOSINGBALANCEMONTH([Stock], DateTable[Date]) retourne :", o: ["Le stock au 1er du mois", "Le stock au dernier jour du mois dans le contexte", "La moyenne mensuelle", "Erreur"], a: 1, d: "VA", ch: 6, w: "CLOSINGBALANCEMONTH retourne la valeur évaluée au dernier jour du mois. Utile pour les stocks et soldes." },
  { q: "Quelle est la cardinalité d'une relation entre DateTable et Sales ?", o: ["N:N", "1:1", "1:N (DateTable est le côté 1)", "N:1"], a: 2, d: "MO", ch: 3, w: "Chaque date apparaît une fois dans DateTable (PK), mais peut avoir N ventes dans Sales (FK). Donc 1:N." },
  { q: "Un analyste veut afficher le rang uniquement dans un tableau (pas dans une Carte). Comment ?", o: ["Impossible", "ISINSCOPE : IF(ISINSCOPE(Product[Name]), RANKX(...), BLANK())", "2 mesures différentes", "Filtre de visuel"], a: 1, d: "MO", ch: 5, w: "ISINSCOPE vérifie si la colonne est dans les groupements du visuel. Si TRUE → afficher le rang, sinon BLANK." },
  { q: "Un Dataflow PQ dans le Service est comparable à :", o: ["Un ETL centralisé et réutilisable dans le cloud", "Un rapport", "Un dashboard", "Un segment"], a: 0, d: "DE", ch: 7, w: "Un Dataflow = Power Query dans le cloud. Les transformations sont partagées entre rapports. Nécessite PPU ou Premium." },
  { q: "Comment tester un rapport sur mobile avant publication ?", o: ["Impossible", "Affichage → Vue mobile dans Desktop pour prévisualiser la mise en page", "Publier et tester sur téléphone", "Réduire la fenêtre Desktop"], a: 1, d: "VA", ch: 7, w: "La vue mobile dans Desktop permet de réorganiser les visuels pour smartphone sans publier." },

  // Multi supplémentaires
  { q: "Quelles fonctions DAX sont des itérateurs ? (2 réponses)", o: ["ALL", "FILTER", "CALCULATE", "MAXX"], a: [1, 3], type: "multi", d: "MO", ch: 5, w: "FILTER et MAXX parcourent une table ligne par ligne. ALL supprime des filtres. CALCULATE modifie le contexte." },
  { q: "Quelles informations sont contenues dans une table de faits ? (2 réponses)", o: ["Clés étrangères (FK) vers les dimensions", "Attributs descriptifs (noms, catégories)", "Mesures numériques (montants, quantités)", "Hiérarchies"], a: [0, 2], type: "multi", d: "MO", ch: 3, w: "Table de faits = FK (pour les jointures) + mesures numériques (pour les calculs). Les attributs descriptifs sont dans les dimensions." },
  { q: "Quelles fonctions retournent une TABLE en DAX ? (2 réponses)", o: ["SUM", "FILTER", "DIVIDE", "ALL"], a: [1, 3], type: "multi", d: "MO", ch: 4, w: "FILTER et ALL retournent des tables. SUM et DIVIDE retournent des scalaires." },
  { q: "Quelles sont les bonnes pratiques pour optimiser un modèle Power BI ? (2 réponses)", o: ["Ajouter le maximum de colonnes", "Supprimer les colonnes inutiles dans PQ", "Utiliser Import plutôt que DirectQuery quand possible", "Garder les types en texte"], a: [1, 2], type: "multi", d: "DE", ch: 7, w: "Moins de colonnes = modèle plus léger. Import = données en cache = plus rapide que DirectQuery." },

  // Order supplémentaires
  { q: "Ordre pour résoudre un bug de visuel vide dans Power BI ?", o: ["Vérifier les mesures DAX", "Vérifier les relations dans le modèle", "Vérifier les types et données dans PQ", "Vérifier les filtres actifs sur le visuel"], a: [2, 1, 0, 3], type: "order", d: "MO", ch: 4, w: "Toujours du bas vers le haut : Données (PQ) → Modèle (relations) → DAX (mesures) → Visuels (filtres)." },
  { q: "Ordre pour déployer un rapport en production ?", o: ["Configurer le refresh planifié", "Tester le RLS", "Publier sur le workspace de production", "Assigner les rôles RLS dans le Service"], a: [1, 2, 0, 3], type: "order", d: "DE", ch: 7, w: "Tester d'abord → Publier → Configurer refresh → Assigner RLS (la sécurité en dernier car elle dépend du dataset publié)." },

  // ─── Section 4.5 — Transition de contexte ───
  { q: "SUMX(Sales, [CA Total]) retourne le même résultat que [CA Total] seul. Pourquoi ?", o: ["Bug DAX", "SUMX ignore la mesure", "La mesure déclenche une transition de contexte — chaque ligne filtre sur elle-même", "SUMX ne fonctionne qu'avec des colonnes"], a: 2, d: "MO", ch: 4, w: "Chaque mesure référencée dans un itérateur invoque implicitement CALCULATE, convertissant le contexte de ligne en contexte de filtre. Chaque ligne est évaluée individuellement puis sommée." },
  { q: "Dans une colonne calculée, Sales[SalesAmount] retourne la valeur de la ligne. Mais [CA Total] retourne le total global. Pourquoi ?", o: ["Colonne calculée ne supporte pas les mesures", "[CA Total] ignore le contexte de ligne — il faut CALCULATE pour la transition", "Bug — les deux devraient donner la même valeur", "Les mesures ne fonctionnent pas dans les colonnes calculées"], a: 1, d: "MO", ch: 4, w: "Sans CALCULATE (implicite via mesure), il n'y a pas de transition de contexte. La mesure s'évalue dans le contexte de filtre global. La référence directe à une colonne utilise le contexte de ligne." },
  { q: "La transition de contexte convertit :", o: ["Le contexte de filtre en contexte de ligne", "Le contexte de ligne en contexte de filtre", "Le contexte de page en contexte de visuel", "Le RLS en filtre de page"], a: 1, d: "MO", ch: 4, w: "CALCULATE convertit le contexte de ligne (row context) en contexte de filtre équivalent. C'est la transition de contexte." },
  { q: "Pourquoi chaque référence à une mesure implique un CALCULATE implicite ?", o: ["Pour des raisons de performance", "C'est un bug historique de DAX", "Pour que les mesures fonctionnent correctement dans les itérateurs et visuels", "Pour forcer le mode Import"], a: 2, d: "MO", ch: 4, w: "Le CALCULATE implicite assure que la mesure est toujours évaluée dans le bon contexte de filtre, que ce soit dans un visuel ou dans un itérateur." },

  // ─── Section 5.6 — SELECTEDVALUE, HASONEVALUE, ISFILTERED ───
  { q: "SELECTEDVALUE(Territory[countryregioncode], \"Tous\") retourne :", o: ["Toujours 'Tous'", "La valeur filtrée si un seul pays est sélectionné, sinon 'Tous'", "Le premier pays de la liste", "Erreur si plusieurs pays"], a: 1, d: "MO", ch: 5, w: "SELECTEDVALUE retourne la valeur unique du contexte de filtre, ou la valeur par défaut si 0 ou plusieurs valeurs sont filtrées." },
  { q: "HASONEVALUE(Territory[countryregioncode]) retourne TRUE quand :", o: ["Au moins un pays est filtré", "Exactement un seul pays est dans le contexte de filtre", "Tous les pays sont sélectionnés", "Aucun filtre n'est actif"], a: 1, d: "MO", ch: 5, w: "HASONEVALUE = TRUE si exactement une valeur distincte existe dans le contexte de filtre pour cette colonne." },
  { q: "ISFILTERED vs ISCROSSFILTERED — quelle est la différence ?", o: ["Identiques", "ISFILTERED = filtre direct sur la colonne, ISCROSSFILTERED = filtre direct ou propagé via relation", "ISFILTERED est plus rapide", "ISCROSSFILTERED ne fonctionne qu'avec Both"], a: 1, d: "MO", ch: 5, w: "ISFILTERED détecte un filtre DIRECT. ISCROSSFILTERED détecte un filtre direct OU propagé via une relation du modèle." },
  { q: "Pour créer un titre dynamique 'CA — France' quand un pays est filtré, sinon 'CA — Tous', quelle approche ?", o: ["IF(ISBLANK(Territory[countryregioncode]), ...)", "SELECTEDVALUE(Territory[countryregioncode], \"Tous\")", "SWITCH(Territory[countryregioncode], ...)", "FILTER(Territory, ...)"], a: 1, d: "MO", ch: 5, w: "SELECTEDVALUE est la forme recommandée pour les titres dynamiques. Elle retourne la valeur unique ou le défaut spécifié." },
  { q: "REMOVEFILTERS est :", o: ["Une nouvelle fonction distincte de ALL", "Un alias de ALL introduit post-2020, fonctionnellement identique", "Une fonction qui supprime uniquement les segments", "Déprécié depuis DAX 2023"], a: 1, d: "MO", ch: 5, w: "REMOVEFILTERS = alias de ALL. Fonctionnellement identique. Microsoft l'a introduit pour plus de clarté sémantique." },

  // ─── Section 7.6 — Performance et optimisation ───
  { q: "Le premier outil à utiliser pour diagnostiquer un rapport lent ?", o: ["DAX Studio", "VertiPaq Analyzer", "Performance Analyzer dans Desktop", "SQL Server Profiler"], a: 2, d: "VA", ch: 7, w: "Performance Analyzer (onglet Affichage) mesure le temps de rendu de chaque visuel. Premier réflexe avant les outils avancés." },
  { q: "Quelle action réduit le PLUS la taille d'un modèle Power BI ?", o: ["Ajouter des index", "Supprimer les colonnes inutiles des tables de faits", "Utiliser DirectQuery au lieu d'Import", "Activer la compression automatique"], a: 1, d: "VA", ch: 7, w: "Les colonnes de texte à haute cardinalité dans les tables de faits (descriptions, commentaires) gonflent le modèle. Les supprimer est l'optimisation la plus efficace." },
  { q: "Pourquoi les colonnes à haute cardinalité dégradent les performances ?", o: ["Elles ralentissent les jointures", "Le moteur VertiPaq compresse par dictionnaire — plus de valeurs uniques = moins de compression", "Elles consomment plus de CPU", "Power BI ne supporte pas plus de 1M de valeurs uniques"], a: 1, d: "VA", ch: 7, w: "VertiPaq utilise le dictionary encoding + run-length encoding. Plus une colonne a de valeurs uniques, moins la compression est efficace, et plus la mémoire RAM est consommée." },
  { q: "Quel est l'avantage principal d'un modèle composite (Import + DirectQuery) ?", o: ["Meilleure sécurité RLS", "Combiner performance (Import pour les dimensions) et fraîcheur (DirectQuery pour les faits volumineuses)", "Réduire le nombre de relations", "Simplifier le modèle en étoile"], a: 1, d: "VA", ch: 7, w: "Le modèle composite permet d'importer les petites tables (dimensions) pour la performance et de garder les grandes tables (faits) en DirectQuery pour la fraîcheur des données." },
  { q: "Gateway Enterprise vs Gateway Personnel — quelle différence clé ?", o: ["Enterprise est gratuit, Personnel est payant", "Enterprise est partagé entre utilisateurs, Personnel est mono-utilisateur", "Personnel est plus rapide", "Enterprise ne supporte pas SQL Server"], a: 1, d: "DE", ch: 7, w: "Enterprise = partagé, géré par IT, plusieurs sources et utilisateurs. Personnel = un seul utilisateur, une seule machine. L'examen PL-300 teste cette distinction." },

  // ─── Section 7.7 — Paramètres What-If ───
  { q: "Un paramètre What-If dans Power BI crée :", o: ["Une colonne calculée dans la table de faits", "Une table déconnectée avec segment et mesure SELECTEDVALUE", "Un filtre de page automatique", "Une relation Many-to-Many avec le modèle"], a: 1, d: "VA", ch: 7, w: "Le paramètre What-If génère une table déconnectée (GENERATESERIES), une colonne, une mesure SELECTEDVALUE et un segment. Aucune relation avec le modèle existant." },
  { q: "Quelle fonction DAX Power BI utilise-t-il en interne pour générer la table d'un paramètre What-If ?", o: ["CALENDAR", "GENERATESERIES", "ADDCOLUMNS", "DATATABLE"], a: 1, d: "VA", ch: 7, w: "GENERATESERIES(min, max, incrément) produit une table à colonne unique contenant la séquence de valeurs numériques du paramètre What-If." },
  { q: "La mesure générée par un paramètre What-If utilise quelle fonction ?", o: ["VALUES", "SELECTEDVALUE", "FIRSTNONBLANK", "CALCULATE"], a: 1, d: "VA", ch: 7, w: "La mesure générée suit le pattern SELECTEDVALUE('Table'[Colonne], ValeurParDéfaut) pour lire la valeur unique sélectionnée dans le segment." },
  { q: "Un paramètre What-If peut-il être relié au modèle de données par une relation ?", o: ["Oui, relation 1:N obligatoire", "Oui, relation Many-to-Many recommandée", "Non, la table est déconnectée par conception", "Oui, mais uniquement via TREATAS"], a: 2, d: "VA", ch: 7, w: "La table What-If est déconnectée par conception. La mesure SELECTEDVALUE est référencée directement dans les calculs de simulation, sans relation." },

  // ─── Section 7.8 — Visuels IA (Key Influencers, Smart Narratives) ───
  { q: "Le visuel Key Influencers accepte dans la zone Explain by :", o: ["Uniquement des mesures", "Uniquement des champs catégoriels ou booléens", "Tout type de champ", "Uniquement des colonnes numériques"], a: 1, d: "VA", ch: 7, w: "Key Influencers utilise un modèle de régression. La zone Explain by n'accepte que des champs catégoriels ou booléens, pas des mesures continues." },
  { q: "Smart Narratives génère du texte qui :", o: ["Est statique une fois créé", "Se met à jour dynamiquement quand les filtres changent", "Nécessite une actualisation manuelle", "Ne fonctionne que dans le Service"], a: 1, d: "VA", ch: 7, w: "Smart Narratives est dynamique : le texte se recalcule automatiquement quand les segments ou filtres de la page changent." },
  { q: "Pour personnaliser le texte d'un Smart Narratives, il faut :", o: ["Modifier le fichier JSON du thème", "Double-cliquer sur le visuel et insérer des variables dynamiques", "Écrire du DAX dans une mesure texte", "Configurer les synonymes du dataset"], a: 1, d: "VA", ch: 7, w: "Double-clic sur le visuel Smart Narratives passe en mode édition. Le bouton '+ Valeur' permet d'insérer des mesures comme variables dynamiques dans le texte." },
  { q: "Key Influencers utilise quel algorithme pour les cibles binaires ?", o: ["K-Means clustering", "Régression logistique", "Arbre de décision", "Réseau de neurones"], a: 1, d: "VA", ch: 7, w: "Pour les cibles binaires (Oui/Non), Key Influencers utilise la régression logistique. Pour les cibles continues, la régression linéaire." },

  // ─── Section 7.8 — Decomposition Tree, Q&R ───
  { q: "L'arbre de décomposition (Decomposition Tree) propose un mode IA qui :", o: ["Génère du texte résumant l'arbre", "Identifie automatiquement la valeur la plus élevée ou la plus basse à chaque niveau", "Crée des relations entre les dimensions", "Prédit les valeurs futures"], a: 1, d: "VA", ch: 7, w: "Le mode IA (High Value / Low Value) identifie automatiquement la dimension et la valeur contribuant le plus ou le moins à la mesure analysée à chaque niveau de l'arbre." },
  { q: "Le visuel Q&R nécessite quelle préparation du modèle pour fonctionner efficacement ?", o: ["Créer des mesures implicites", "Configurer les synonymes dans les paramètres du dataset", "Activer DirectQuery", "Installer un Gateway"], a: 1, d: "VA", ch: 7, w: "Les synonymes permettent au moteur Q&R de comprendre les questions en langage naturel. Configurer SalesAmount → 'CA', 'ventes', countryregioncode → 'pays', etc." },
  { q: "Quel visuel permet d'explorer les contributeurs d'une mesure de manière hiérarchique et interactive ?", o: ["Key Influencers", "Smart Narratives", "Decomposition Tree", "Q&R"], a: 2, d: "VA", ch: 7, w: "L'arbre de décomposition (Decomposition Tree) ventile une mesure par niveaux hiérarchiques successifs. L'utilisateur choisit la dimension à chaque niveau ou laisse l'IA décider." },
  { q: "Quelle combinaison de visuels IA répond à : analyse causale + résumé textuel + exploration libre ?", o: ["Key Influencers + Smart Narratives + Q&R", "Decomposition Tree + Matrice + Zone de texte", "Q&R + Histogramme + Carte KPI", "Smart Narratives + Table + Segment"], a: 0, d: "VA", ch: 7, w: "Key Influencers = analyse causale (facteurs d'impact). Smart Narratives = résumé textuel dynamique. Q&R = exploration libre en langage naturel. Chaque visuel IA couvre un besoin analytique distinct." },

  // ─── PQ — Types de données ───
  { q: "Une colonne contient '12/03/2024' mais Power Query la détecte en texte. Quelle action corriger ?", o: ["Créer une colonne calculée DAX", "Modifier le type en Date dans l'éditeur PQ", "Utiliser FORMAT() dans une mesure", "Aucune — PQ détecte toujours correctement"], a: 1, d: "PQ", ch: 2, w: "Power Query se base sur les 200 premières lignes pour détecter le type. Si le format est ambigu, il peut choisir Texte. Il faut corriger manuellement via Modifier le type." },
  { q: "Power Query analyse combien de lignes par défaut pour détecter automatiquement les types de colonnes ?", o: ["Toutes les lignes", "1 000 premières lignes", "200 premières lignes", "50 premières lignes"], a: 2, d: "PQ", ch: 2, w: "Par défaut, Power Query analyse les 200 premières lignes. Si les données sont hétérogènes au-delà, le type détecté peut être incorrect." },
  { q: "Quel est le risque de charger une colonne numérique détectée en texte dans le modèle ?", o: ["Aucun — DAX convertit automatiquement", "Les agrégations SUM/AVERAGE échoueront ou donneront des résultats incorrects", "Le fichier .pbix sera corrompu", "Le rafraîchissement sera plus rapide"], a: 1, d: "PQ", ch: 2, w: "Une colonne texte ne peut pas être agrégée directement par SUM ou AVERAGE. DAX peut tenter une conversion implicite mais le comportement est imprévisible et les performances dégradées." },

  // ─── PQ — Column Quality / Distribution / Profile ───
  { q: "Dans Power Query, Column Quality affiche :", o: ["Le pourcentage de valeurs valides, en erreur et vides", "La distribution des valeurs distinctes", "Les statistiques min/max/moyenne", "Le type de données détecté"], a: 0, d: "PQ", ch: 2, w: "Column Quality montre trois pourcentages : Valid (valide), Error (erreur) et Empty (vide) pour chaque colonne." },
  { q: "Column Profile dans Power Query affiche des statistiques sur :", o: ["Les 200 premières lignes uniquement par défaut", "Toutes les lignes automatiquement", "Seulement les colonnes numériques", "Les colonnes sélectionnées manuellement"], a: 0, d: "PQ", ch: 2, w: "Par défaut, Column Profile analyse les 1 000 premières lignes. Pour analyser toutes les lignes, modifier le paramètre dans la barre d'état : Column profiling based on entire data set." },

  // ─── PQ — Fill Down ───
  { q: "Un fichier Excel contient des cellules fusionnées dans la colonne Catégorie. Après import dans PQ, les lignes fusionnées apparaissent comme :", o: ["Valeur répétée sur chaque ligne", "null sur les lignes sous la première", "Erreur #REF", "Cellule vide supprimée"], a: 1, d: "PQ", ch: 2, w: "Power Query ne reconnaît pas les cellules fusionnées Excel. Seule la première ligne contient la valeur, les suivantes sont null. Utiliser Fill Down pour propager la valeur." },
  { q: "Quelle transformation PQ propage la dernière valeur non-null vers les lignes vides en dessous ?", o: ["Replace Values", "Fill Up", "Fill Down", "Group By"], a: 2, d: "PQ", ch: 2, w: "Fill Down copie la dernière valeur non-null vers les cellules null en dessous. Idéal après import de fichiers Excel avec cellules fusionnées." },

  // ─── PQ — Replace Errors ───
  { q: "Quelle est la différence entre Replace Errors et Replace Values dans Power Query ?", o: ["Identiques — les deux remplacent null", "Replace Errors cible les erreurs (#REF, division/0), Replace Values cible les valeurs normales", "Replace Errors est plus lent", "Replace Values ne fonctionne que sur le texte"], a: 1, d: "PQ", ch: 2, w: "Replace Errors remplace les cellules en erreur (division par zéro, type incorrect, etc.) par une valeur définie (null, 0, texte). Replace Values remplace une valeur spécifique par une autre." },
  { q: "Pour remplacer les erreurs d'une colonne numérique par null dans PQ, quelle étape utiliser ?", o: ["Replace Values avec 0", "Remove Errors", "Replace Errors avec null", "Fill Down"], a: 2, d: "PQ", ch: 2, w: "Replace Errors permet de remplacer toutes les erreurs d'une colonne par la valeur choisie (null, 0, texte vide). Remove Errors supprime les lignes entières contenant des erreurs." },

  // ─── PQ — Query Folding ───
  { q: "Le Query Folding dans Power Query signifie que :", o: ["Les étapes sont exécutées côté serveur (SQL natif) au lieu de localement", "Les requêtes sont compressées pour réduire la taille du fichier", "Les colonnes sont pliées (masquées) dans l'éditeur", "Les tables sont fusionnées automatiquement"], a: 0, d: "PQ", ch: 2, w: "Le Query Folding traduit les étapes PQ en requêtes SQL natives exécutées directement par la source (SQL Server, etc.). Cela améliore considérablement les performances." },
  { q: "Comment vérifier si le Query Folding est actif sur une étape PQ ?", o: ["Le bouton Actualiser devient vert", "Clic droit sur l'étape → Afficher la requête native (View Native Query)", "L'étape affiche un éclair dans la barre latérale", "Impossible à vérifier — c'est automatique"], a: 1, d: "PQ", ch: 2, w: "Clic droit sur une étape → View Native Query. Si l'option est grisée, le folding est cassé à cette étape ou en amont." },
  { q: "Laquelle de ces opérations casse généralement le Query Folding ?", o: ["Filtrer des lignes", "Supprimer des colonnes", "Ajouter une colonne personnalisée avec formule M", "Renommer une colonne"], a: 2, d: "PQ", ch: 2, w: "Les colonnes personnalisées avec formule M (ex: Text.Upper, calculs complexes) ne peuvent pas être traduites en SQL natif et cassent le folding. Filtrer, supprimer ou renommer des colonnes sont généralement pliables." },

  // ─── PQ — Combine from Folder ───
  { q: "La fonctionnalité Combine from Folder dans PQ permet de :", o: ["Fusionner deux tables sur une clé commune", "Charger automatiquement tous les fichiers d'un dossier et les empiler", "Créer des sous-dossiers dans le dataset", "Compresser les fichiers avant import"], a: 1, d: "PQ", ch: 2, w: "Combine from Folder charge tous les fichiers (Excel, CSV, etc.) d'un dossier, applique les mêmes transformations à chacun et les empile (append). Les nouveaux fichiers ajoutés au dossier sont inclus au prochain rafraîchissement." },
  { q: "Après avoir configuré Combine from Folder, un collègue ajoute un nouveau fichier CSV dans le dossier source. Que se passe-t-il au prochain refresh ?", o: ["Le nouveau fichier est ignoré", "Le nouveau fichier est automatiquement inclus", "Une erreur se produit car le schéma a changé", "Il faut reconfigurer la requête"], a: 1, d: "PQ", ch: 2, w: "Combine from Folder détecte dynamiquement tous les fichiers du dossier à chaque rafraîchissement. Les nouveaux fichiers conformes au schéma sont automatiquement inclus." },

  // ─── PQ — Parameters et Incremental Refresh ───
  { q: "Les paramètres RangeStart et RangeEnd dans Power Query servent principalement à :", o: ["Filtrer les données pour le rafraîchissement incrémentiel", "Définir les bornes d'un axe de graphique", "Limiter le nombre de lignes affichées", "Configurer la pagination du rapport"], a: 0, d: "PQ", ch: 2, w: "RangeStart et RangeEnd sont des paramètres réservés utilisés par le rafraîchissement incrémentiel pour ne charger que les données de la période concernée au lieu de tout recharger." },

  // ─── PQ — M language basics ───
  { q: "Dans le langage M de Power Query, la structure de base d'une requête est :", o: ["SELECT ... FROM ... WHERE", "let ... in ...", "function() { return ... }", "BEGIN ... END"], a: 1, d: "PQ", ch: 2, w: "Le langage M utilise la structure let/in : let définit les variables (étapes), in retourne le résultat final. Chaque étape peut référencer les précédentes." },
  { q: "La fonction Table.TransformColumnTypes en M sert à :", o: ["Renommer les colonnes d'une table", "Modifier les types de données des colonnes", "Supprimer les colonnes d'un type spécifique", "Trier les colonnes par type"], a: 1, d: "PQ", ch: 2, w: "Table.TransformColumnTypes modifie le type de données d'une ou plusieurs colonnes. C'est la fonction générée automatiquement quand on change un type dans l'interface PQ." },

  // ─── PQ — Append vs Merge ───
  { q: "Append Queries dans PQ empile les lignes de deux tables. Si les colonnes ne correspondent pas exactement :", o: ["L'opération échoue avec une erreur", "Les colonnes manquantes sont remplies avec null", "Les colonnes supplémentaires sont supprimées", "PQ renomme automatiquement les colonnes"], a: 1, d: "PQ", ch: 2, w: "Append tolère les différences de colonnes : les colonnes présentes dans une table mais absentes de l'autre sont remplies avec null. Aucune erreur n'est générée." },
  { q: "Quelle jointure Merge utiliser pour garder toutes les lignes de la table de gauche, même sans correspondance ?", o: ["Inner Join", "Left Outer Join", "Right Outer Join", "Full Outer Join"], a: 1, d: "PQ", ch: 2, w: "Left Outer Join conserve toutes les lignes de la première table (gauche). Les lignes sans correspondance dans la table de droite ont des valeurs null pour les colonnes de droite." },

  // ─── VA — Mise en forme conditionnelle ───
  { q: "Quels types de mise en forme conditionnelle sont disponibles dans Power BI ? (choix unique)", o: ["Échelle de couleurs, règles, barres de données, icônes", "Uniquement les échelles de couleurs", "Uniquement les barres de données", "Mise en forme conditionnelle par formule DAX uniquement"], a: 0, d: "VA", ch: 7, w: "Power BI propose 4 types : échelle de couleurs (gradient), règles (si > X alors couleur), barres de données (barres horizontales) et jeux d'icônes (flèches, étoiles, etc.)." },
  { q: "La mise en forme conditionnelle par règles est applicable sur :", o: ["Tous les types de visuels", "Tables et matrices uniquement", "Graphiques à barres uniquement", "Cartes KPI uniquement"], a: 1, d: "VA", ch: 7, w: "La mise en forme conditionnelle (couleur de fond, couleur de police, barres, icônes) est disponible dans les tables et les matrices. Les autres visuels ont des options limitées." },

  // ─── VA — What-If Parameters ───
  { q: "Un paramètre What-If dans Power BI génère automatiquement :", o: ["Une mesure DAX uniquement", "Une table déconnectée (GENERATESERIES) + un segment + une mesure SELECTEDVALUE", "Un filtre de page", "Une colonne calculée dans la table de faits"], a: 1, d: "VA", ch: 7, w: "Le paramètre What-If crée : une table déconnectée via GENERATESERIES (valeurs min/max/pas), un segment (slicer) pour choisir la valeur, et une mesure utilisant SELECTEDVALUE pour récupérer la valeur sélectionnée." },
  { q: "GENERATESERIES(1, 10, 1) retourne :", o: ["Un scalaire égal à 10", "Une table d'une colonne avec les valeurs 1, 2, 3, ..., 10", "Une table vide", "Un filtre sur les nombres de 1 à 10"], a: 1, d: "VA", ch: 7, w: "GENERATESERIES(start, end, step) génère une table d'une seule colonne [Value] contenant les valeurs de start à end par incréments de step." },

  // ─── VA — Navigation rapport ───
  { q: "Les signets (bookmarks) dans Power BI capturent :", o: ["Uniquement les filtres actifs", "L'état complet de la page : filtres, segments, visibilité des visuels, position de la page", "Uniquement la mise en page", "Les données source"], a: 1, d: "VA", ch: 7, w: "Un signet capture l'état complet : filtres, segments (slicers), visibilité des visuels, ordre de tri, et éventuellement la position de la page. Ils permettent de créer des scénarios de navigation." },
  { q: "Le drillthrough cross-report permet de :", o: ["Naviguer d'un visuel à un autre dans la même page", "Naviguer d'un rapport vers une page de détail dans un autre rapport", "Filtrer tous les visuels de la page", "Exporter les données vers Excel"], a: 1, d: "VA", ch: 7, w: "Le drillthrough cross-report permet de cliquer-droit sur une valeur dans un rapport et naviguer vers une page détaillée dans un autre rapport, en passant le contexte de filtre." },

  // ─── VA — Small Multiples ───
  { q: "Les Small Multiples dans Power BI permettent de :", o: ["Afficher le même visuel répété pour chaque valeur d'une catégorie", "Réduire la taille des visuels automatiquement", "Créer des miniatures de chaque page du rapport", "Dupliquer un visuel sur plusieurs pages"], a: 0, d: "VA", ch: 7, w: "Les Small Multiples divisent un visuel (barres, lignes, aires) en une grille où chaque cellule montre le même graphique filtré par une valeur de la catégorie choisie. Utile pour comparer des tendances par segment." },

  // ─── VA — Anomaly Detection / Forecasting ───
  { q: "La détection d'anomalies dans Power BI est disponible sur :", o: ["Tous les types de visuels", "Les graphiques en courbes (line charts) uniquement", "Les tables et matrices", "Les graphiques à barres empilées"], a: 1, d: "VA", ch: 7, w: "La détection d'anomalies et les prévisions (forecasting) ne sont disponibles que sur les graphiques en courbes (line charts). Power BI utilise un algorithme de détection automatique des points inhabituels." },
  { q: "La fonctionnalité Forecast dans Power BI nécessite :", o: ["Un visuel de type ligne avec un axe de date continu", "N'importe quel visuel avec une mesure", "Un modèle DirectQuery", "Une licence Premium"], a: 0, d: "VA", ch: 7, w: "Le Forecast nécessite un graphique en courbes avec un axe temporel continu (dates). Power BI utilise un modèle de lissage exponentiel pour projeter les valeurs futures avec intervalle de confiance." }
];

